insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (1, 1, 0, '', 190804, 0, 'カリン', 60000, 1, 1, '新年を迎え、新たに始まる一日を\\nおみくじで占ってみませんか？\\n良い運勢であるほど、\\n沢山のプレゼントが貰えますよ♪', 0);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (2, 0, 1, '', 0, 0, '', 60000, 1, 2, '今日の運勢は姫吉！\u3000あらゆる運気が最大を示しています！\u3000\u3000\u3000今なら「伝説の吸血鬼」をも従え、世界征服も夢じゃありません！', 0);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (3, 0, 1, '', 0, 0, '', 60000, 1, 2, '今日の運勢は姫吉！\u3000やること全てが最高潮！\u3000やばいですね☆\u3000ラッキーアイテムはおにぎり！\u3000お腹一杯で幸せが続くでしょう！', 0);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (4, 0, 1, '', 0, 0, '', 60000, 2, 2, '今日の運勢は姫吉！\u3000その高い運気はまさにショーグンの如く！\u3000その溢れる威光は人々を惹きつけ、皆の人気者間違いなしです！', 0);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (5, 0, 2, '', 0, 0, '', 60000, 1, 2, '今日の運勢は大吉！\u3000運気がどんどん高まっています！\u3000\u3000\u3000\u3000\u3000何をやっても、最大効率で素晴らしい結果になりますよ♪', 0);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (6, 0, 2, '', 0, 0, '', 60000, 1, 2, '今日の運勢は大吉！\u3000なにをやっても上手くいって大活躍！\u3000\u3000\u3000そんな素敵なあなたを見て、後ろから誰かが……クスクス♪', 0);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (7, 0, 2, '', 0, 0, '', 60000, 2, 2, '今日の運勢は大吉！\u3000運気が高く、何かに挑戦すると良い結果に！隠れた才能が引き出されそう！\u3000目指せヒデサ……ではなく秀才！', 0);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (8, 0, 3, '', 0, 0, '', 60000, 1, 2, '今日の運勢は中吉！\u3000商売運が上がってきています！\u3000\u3000\u3000\u3000\u3000\u3000ラッキーアイテムはたいやき！\u3000和菓子パワーで売上アップです！', 0);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (9, 0, 3, '', 0, 0, '', 60000, 1, 2, '今日の運勢は中吉！\u3000旅行運がぐんぐんと上昇中♪\u3000\u3000\u3000\u3000\u3000\u3000\u3000もしかしたら、あの「マホマホ王国」にだって行けるかも♪', 0);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (10, 0, 3, '', 0, 0, '', 60000, 1, 2, '今日の運勢は中吉！\u3000仕事運が急上昇中です！\u3000\u3000\u3000\u3000\u3000\u3000\u3000\u3000\u3000きっと「煉獄に舞う一陣の疾風」の如き活躍ができますよ！', 0);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (11, 0, 3, '', 0, 0, '', 60000, 1, 2, '今日の運勢は中吉！\u3000チャンスを待つと良い結果に！\u3000\u3000\u3000\u3000\u3000\u3000ラッキーアイテムのプリンを食べて、運を呼び込みましょう！', 0);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (12, 0, 3, '', 0, 0, '', 60000, 2, 2, '今日の運勢は中吉！\u3000運気が着々と上昇中！\u3000\u3000\u3000\u3000\u3000\u3000\u3000\u3000\u3000\u3000精霊の加護を受けたかの如く、色々な事がうまくいきますよ♪', 0);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (13, 0, 4, '', 0, 0, '', 60000, 1, 2, '今日の運勢は小吉！\u3000早朝に幸運の兆しあり！\u3000\u3000\u3000\u3000\u3000\u3000\u3000\u3000\u3000もしかしたら、優しいお姉ちゃんが起こしにきてくれますよ♪', 0);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (14, 0, 4, '', 0, 0, '', 60000, 1, 2, '今日の運勢は小吉！\u3000運気上昇中ですが、上がるまでが要注意！\u3000ラッキーアニマルは熊！\u3000本当の家族のように守ってくれるかも♪', 0);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (15, 0, 4, '', 0, 0, '', 60000, 1, 2, '今日の運勢は小吉！\u3000外に出てゆっくり過ごすと運気が上昇！\u3000\u3000ラッキースポットは牧場。面白い出会いがありそうです♪', 0);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (16, 0, 4, '', 0, 0, '', 60000, 1, 2, '今日の運勢は小吉！\u3000運気は高いけども、ハプニングには注意！\u3000出かけた先で、「ふしんしゃ」扱いされてしまうかも……', 0);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (17, 0, 4, '', 0, 0, '', 60000, 2, 2, '今日の運勢は小吉！\u3000根を詰めずにリラックスすると運気向上！\u3000ラッキーパーソンはアイドル。歌があなたを幸せにしてくれます♪', 0);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (18, 2, 0, '', 190804, 0, 'カリン', 60000, 0, 3, 'おみくじの結果はどうでしたか？\\n新たに始まる一日が、あなたに\\nとって良い日になりますように\\nまた明日も遊びに来て下さいね♪', 0);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (19, 3, 0, '', 190804, 7, 'カリン', 60000, 0, 3, 'おみくじは楽しんで頂けましたか？\\nあなたの新たなる年が\\n素晴らしいものになるよう、\\n心からお祈りいたします', 0);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (20, 1, 0, '', 101201, 1, 'ハツネ', 80001, 0, 0, 'キミと出会ってもう\\n1年もたつんだね！\\nう～ん、いつも\\n寝てばっかりだから、', 0);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (21, 2, 0, '', 101201, 1, 'ハツネ', 80001, 0, 0, '少しでも\\n寝る時間を減らして\\nキミと一緒にいる\\n時間増やしたいなぁ♪', 0);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (22, 1, 0, '', 103801, 1, 'シオリ', 80001, 0, 1, 'あなたと知り合ってから\\nもう1年…\\n時がたつのは\\n早いですね', 0);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (23, 2, 0, '', 103801, 1, 'シオリ', 80001, 0, 1, '来年も、\\n一緒にいられたら…\\nうれしいな', 0);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (24, 1, 0, '', 103601, 2, 'キョウカ', 80001, 0, 0, 'あなたと一緒にいるようになって、\\nもう1年ですか…', 0);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (25, 2, 0, '', 103601, 2, 'キョウカ', 80001, 0, 0, '最初の頃よりも、頼もしく\\nなりましたね。私はどうですか？\\n成長していますか？', 0);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (26, 1, 0, '', 102001, 2, 'ミミ', 80001, 0, 1, 'おにいちゃんとあってから、\\n1年たったよ～！', 0);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (27, 2, 0, '', 102001, 2, 'ミミ', 80001, 0, 1, 'ミミね、おにいちゃんと\\nいっぱい遊べてたのしかったな～♪\\nこれからもずっと\\nいっしょにいてね～！', 0);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (28, 1, 0, '', 100401, 2, 'ミソギ', 80001, 0, 2, 'にいちゃんがミソギのイタズラに\\n引っかかり続けてもう1年かぁ', 0);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (29, 2, 0, '', 100401, 2, 'ミソギ', 80001, 0, 2, '…これからもいっぱいミソギと\\n遊んでね、にいちゃん！', 0);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (30, 1, 0, '', 101001, 3, 'マホ', 80001, 0, 0, 'もう王子はんと会うてから\\n1年ぐらいたつそうどすえ\\n早いもんやなあ', 0);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (31, 2, 0, '', 101001, 3, 'マホ', 80001, 0, 0, 'このままやと、\\nうちもあっという間に\\n干からびてしまいそうどすえ\\nなーんてな。うふふ', 0);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (32, 1, 0, '', 104401, 3, 'イリヤ', 80001, 0, 1, 'お主と会って早1年じゃな\\nこれからも存分に尽くすがよい', 0);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (33, 2, 0, '', 104401, 3, 'イリヤ', 80001, 0, 1, 'わらわもたまには、お主の献身に\\n報いてやらぬでもない♪', 0);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (34, 1, 0, '', 101701, 3, 'カオリ', 80001, 0, 2, 'もう、キミと出会って結構な時間が\\nたつさ～。でも、私たちの旅は\\nまだまだ始まったばかりさ～！', 0);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (35, 2, 0, '', 101701, 3, 'カオリ', 80001, 0, 2, 'これからも、どうぞよろしく\\nお願いするさ～！', 0);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (36, 1, 0, '', 102801, 4, 'サレン', 80001, 0, 0, 'あんたと出会ってからもうそんなに\\nたつのね～', 0);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (37, 2, 0, '', 102801, 4, 'サレン', 80001, 0, 0, 'あっという間だったって感じるほど\\n楽しかったわ！\\nこれからも一緒に頑張りましょ！', 0);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (38, 1, 0, '', 102501, 4, 'スズメ', 80001, 0, 1, '出会ってから1年間、ずっと\\nご迷惑をかけっぱなしで、\\nすみません…', 0);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (39, 2, 0, '', 102501, 4, 'スズメ', 80001, 0, 1, 'これからはもっと頑張りますから\\n見ていてくださいね\\nできれば…\\n今までよりも、私の近くで♪', 0);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (40, 1, 0, '', 104601, 5, 'タマキ', 80001, 0, 0, '振り返れば、今までいろんなことが\\nあったにゃあ…', 0);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (41, 2, 0, '', 104601, 5, 'タマキ', 80001, 0, 0, 'これからも、二人でたくさんの\\n思い出をがっぽり作っていく\\nにゃー！', 0);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (42, 1, 0, '', 104801, 5, 'ミフユ', 80001, 0, 1, 'キミとの師弟関係も、\\nもう1年なのね…\\nでもキミに教えることは、', 0);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (43, 2, 0, '', 104801, 5, 'ミフユ', 80001, 0, 1, 'まだまだいっぱいあるわ\\nこれからも、\\nしっかりついて来てね！', 0);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (44, 1, 0, '', 103201, 6, 'アキノ', 80001, 0, 0, 'あなたさまと出会ってもう1年…', 0);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (45, 2, 0, '', 103201, 6, 'アキノ', 80001, 0, 0, '光陰矢のごとし、とはまさに\\nこのことですわ。…思い出は決して\\nお金では買えませんわね', 0);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (46, 1, 0, '', 103401, 6, 'ユカリ', 80001, 0, 1, 'ダメな私を1年間も見捨てないで\\nくれて、本当にありがとう', 0);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (47, 2, 0, '', 103401, 6, 'ユカリ', 80001, 0, 1, '情けないところいっぱいみせるかも\\nしれないけど、これからも一緒に\\nいてくれると、うれしいな', 0);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (48, 1, 0, '', 107101, 7, 'クリスティーナ', 80001, 0, 0, 'オマエと出会ってもう1年か\\nまさかこのワタシの結婚相手に\\nなろうとはな…', 0);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (49, 2, 0, '', 107101, 7, 'クリスティーナ', 80001, 0, 0, 'ともかくこれからも\\n愉しませてくれよ☆', 0);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (50, 1, 0, '', 104701, 7, 'ジュン', 80001, 0, 1, '君と出会ってからもう1年か。\\n以前と比べて私の表情もいくらか\\n柔らかくなった気がするんだが、\\nどうだろう？', 0);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (51, 2, 0, '', 104701, 7, 'ジュン', 80001, 0, 1, '見えないから分からないって？\\nそれもそうだな…', 0);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (52, 1, 0, '', 103701, 8, 'トモ', 80001, 0, 0, 'もう1年たったみたいだね\\nあなたをからかってばかりだった\\nけど、楽しかった♪', 0);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (53, 2, 0, '', 103701, 8, 'トモ', 80001, 0, 0, 'これからもよろしくね！', 0);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (54, 1, 0, '', 100501, 8, 'マツリ', 80001, 0, 1, '出会って、もう1年たっちゃった\\nんスね。なんだか意外ッス', 0);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (55, 2, 0, '', 100501, 8, 'マツリ', 80001, 0, 1, '毎日楽しくて、あっという間に過ぎ\\nちゃったみたいなんスよね\\nこれからも一緒に悪と戦うッス！', 0);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (56, 1, 0, '', 100701, 9, 'ミヤコ', 80001, 0, 0, 'オマエと会って1年なの！\\n全然成仏もできなかったし、', 0);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (57, 2, 0, '', 100701, 9, 'ミヤコ', 80001, 0, 0, '生き返りもしなかったけど、\\nすごく楽しかったの～♪\\nオマエとプリンがあれば、\\nミヤコはハッピーなの～♪', 0);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (58, 1, 0, '', 103101, 9, 'シノブ', 80001, 0, 1, 'あなたと出会って1年なんですね\\nでも、私の占いでは、私とあなたは', 0);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (59, 2, 0, '', 103101, 9, 'シノブ', 80001, 0, 1, '来年も再来年も一緒にいるようです\\nふふ、よろしくお願いしますね', 0);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (60, 1, 0, '', 100901, 10, 'アンナ', 80001, 0, 0, '貴様が閃光のシグルドとして覚醒し\\nもう1年か…。これからも我らの\\n長き戦いに終わりはないが、', 0);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (61, 2, 0, '', 100901, 10, 'アンナ', 80001, 0, 0, 'それでも貴様となら…\\n添い遂げる覚悟はできているぞ！', 0);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (62, 1, 0, '', 101301, 10, 'ナナカ', 80001, 0, 1, '君と出会ってもう1年だって！\\n早いねー！', 0);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (63, 2, 0, '', 101301, 10, 'ナナカ', 80001, 0, 1, 'これからも最強のバディタッグで\\n大活躍だー！\\n頼りにしてるよ、相棒！', 0);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (64, 1, 0, '', 105101, 11, 'ミツキ', 80001, 0, 0, '1年たつのって、あっという間ね\\nまだまだ君の知らない部分が\\nたくさんあるし…', 0);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (65, 2, 0, '', 105101, 11, 'ミツキ', 80001, 0, 0, 'これからも、いろんなところを\\n調べさせてね？', 0);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (66, 1, 0, '', 105601, 11, 'ルカ', 80001, 0, 1, 'お前さんと出会ってもう1年か\\n助太刀するつもりが', 0);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (67, 2, 0, '', 105601, 11, 'ルカ', 80001, 0, 1, '逆に助けられたりもしたね\\nこれからもよろしく頼むよ！', 0);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (68, 1, 0, '', 102701, 11, 'エリコ', 80001, 0, 2, '早いものですわね、あなた様と\\nお会いして、もう1年…', 0);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (69, 2, 0, '', 102701, 11, 'エリコ', 80001, 0, 2, 'あなた様といると、時があっと\\nいう間に過ぎてしまいます\\n時間を止める研究をしなくては\\nいけませんね…', 0);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (70, 1, 0, '', 102301, 12, 'アヤネ', 80001, 0, 0, 'お兄ちゃんと会ってから、もう、\\n1年なんだね。私、少しは\\nお姉ちゃんっぽくなったかな？', 0);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (71, 2, 0, '', 102301, 12, 'アヤネ', 80001, 0, 0, 'あ、ぷうきちもお兄ちゃんっぽく\\nなったよね？', 0);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (72, 1, 0, '', 104201, 12, 'チカ', 80001, 0, 1, 'あなたと出会って、\\nもう1年がたったんですね…\\nこれからもそばにいて、', 0);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (73, 2, 0, '', 104201, 12, 'チカ', 80001, 0, 1, '私のことを見守ってください\\nできることなら、ずっと…', 0);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (74, 1, 0, '', 102101, 12, 'クルミ', 80001, 0, 2, 'お兄ちゃんと出会って1年かぁ\\n私、相変わらずダメダメで…', 0);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (75, 2, 0, '', 102101, 12, 'クルミ', 80001, 0, 2, 'で、でもこれからもずっと…\\n一緒にいたいなぁ…', 0);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (76, 1, 0, '', 104901, 13, 'シズル', 80001, 0, 0, '再会してちょうど1年だね\\nお祝いにごちそう作ってきたよ～♪\\n特製ケーキと、お寿司と、', 0);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (77, 2, 0, '', 104901, 13, 'シズル', 80001, 0, 0, 'ハンバーグと、カレーと、\\nシチューと、あ、隠しきれない隠し\\n味は、お姉ちゃんの愛情だよ！', 0);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (78, 1, 0, '', 101101, 13, 'リノ', 80001, 0, 1, 'お兄ちゃんと再会して、もう1年\\nなんですね。\\n会えなかった時を思うと、', 0);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (79, 2, 0, '', 101101, 13, 'リノ', 80001, 0, 1, '信じられないくらい幸せな1年\\nでした！もう絶対、私から離れ\\nないでくださいね♪', 0);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (80, 1, 0, '', 100201, 14, 'ユイ', 80001, 0, 0, '騎士クンと出会ってから今まで、\\nいろんなことがあったよね\\n楽しいこと、ドキドキしたこと…', 0);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (81, 2, 0, '', 100201, 14, 'ユイ', 80001, 0, 0, 'そんな日々をこれからも、\\nず、ずっと一緒に…\\n過ごしていきたいな…！', 0);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (82, 1, 0, '', 100101, 14, 'ヒヨリ', 80001, 0, 1, '騎士くんと出会って、まだ1年しか\\nたってないんだ！？', 0);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (83, 2, 0, '', 100101, 14, 'ヒヨリ', 80001, 0, 1, 'なんかもうずっと一緒にいる気が\\nするなぁ…えへへ。これからの\\n1年もまたよろしくねっ！\\n騎士くん！', 0);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (84, 1, 0, '', 100301, 14, 'レイ', 80001, 0, 2, '初めてキミに出会って1年…\\n随分見違えたね私もキミも、\\n更に強くなっていく…', 0);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (85, 2, 0, '', 100301, 14, 'レイ', 80001, 0, 2, 'キミに背中を預けられる日が、\\n早くきますように', 0);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (86, 1, 0, '', 105801, 15, 'ペコリーヌ', 80001, 0, 0, '1年もわたしのことを、忘れない\\nでいてくれて、ありがとうござい\\nます！', 0);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (87, 2, 0, '', 105801, 15, 'ペコリーヌ', 80001, 0, 0, 'これからもずっと、覚えていて\\nくださいね！', 0);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (88, 1, 0, '', 105901, 15, 'コッコロ', 80001, 0, 1, 'こうして1年も、主さまのおそばに\\n置いていただけて、とても光栄\\nです。どうかこれからも、', 0);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (89, 2, 0, '', 105901, 15, 'コッコロ', 80001, 0, 1, '末永く主さまをお世話させて\\nください。わたくしは、ずっと\\n主さまのガイド役でいたいのです', 0);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (90, 1, 0, '', 106001, 15, 'キャル', 80001, 0, 2, '1年か、まっさかこんなに長い\\n付き合いになるなんてね～\\nでも…わりと楽しい1年だったかも', 0);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (91, 2, 0, '', 106001, 15, 'キャル', 80001, 0, 2, 'だから、もうしばらくあんたに\\n付き合ってやるわよ喜びなさい！', 0);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (92, 1, 0, '', 112101, 0, 'スズメ', 60001, 1, 1, '新しい年のはじめに、\\nおみくじはいかがでしょうか？\\nよい運勢であるほど、\\n沢山プレゼントが貰えますよ♪', 0);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (93, 0, 1, '', 0, 0, '', 60001, 1, 2, '今日の運勢は姫吉！\u3000あらゆる運気が最大を示しています！\u3000\u3000\u3000今なら「伝説の吸血鬼」をも従え、世界征服も夢じゃありません！', 0);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (94, 0, 1, '', 0, 0, '', 60001, 1, 2, '今日の運勢は姫吉！\u3000やること全てが最高潮！\u3000やばいですね☆\u3000ラッキーアイテムはおにぎり！\u3000お腹一杯で幸せが続くでしょう！', 0);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (95, 0, 1, '', 0, 0, '', 60001, 1, 2, '今日の運勢は姫吉！\u3000最強の運勢でどんなドジも跳ね除けます！\u3000大切な人と一緒に、最高の一日になること間違いなし！', 0);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (96, 0, 1, '', 0, 0, '', 60001, 1, 2, '今日の運勢は姫吉！\u3000どんな挑戦も上手くいく、最高の運勢です！理想の自分に変身できる絶好の機会！\u3000新しい一歩を踏み出そう！', 0);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (97, 0, 1, '', 0, 0, '', 60001, 2, 2, '今日の運勢は姫吉！\u3000その高い運気はまさにショーグンの如く！\u3000その溢れる威光は人々を惹きつけ、皆の人気者間違いなしです！', 0);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (98, 0, 2, '', 0, 0, '', 60001, 1, 2, '今日の運勢は大吉！\u3000運気がどんどん高まっています！\u3000\u3000\u3000\u3000\u3000何をやっても、最大効率で素晴らしい結果になりますよ♪', 0);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (99, 0, 2, '', 0, 0, '', 60001, 1, 2, '今日の運勢は大吉！\u3000なにをやっても上手くいって大活躍！\u3000\u3000\u3000そんな素敵なあなたを見て、後ろから誰かが……クスクス♪', 0);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (100, 0, 2, '', 0, 0, '', 60001, 1, 2, '今日の運勢は大吉！\u3000ラッキーワードは「ちぇる～ん♪」\u3000\u3000\u3000\u3000出会う人みんなに言ってあげると、ハッピーになれますよ！', 0);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (101, 0, 2, '', 0, 0, '', 60001, 1, 2, '今日の運勢は大吉！\u3000運勢はバッチリで無敵状態！\u3000\u3000\u3000\u3000\u3000\u3000\u3000龍眼で全てを見通して、思い通りの一日を過ごしましょう！', 0);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (102, 0, 2, '', 0, 0, '', 60001, 2, 2, '今日の運勢は大吉！\u3000運気が高く、何かに挑戦すると良い結果に！隠れた才能が引き出されそう！\u3000目指せヒデサ……ではなく秀才！', 0);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (103, 0, 3, '', 0, 0, '', 60001, 1, 2, '今日の運勢は中吉！\u3000商売運が上がってきています！\u3000\u3000\u3000\u3000\u3000\u3000ラッキーアイテムはたいやき！\u3000和菓子パワーで売上アップです！', 0);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (104, 0, 3, '', 0, 0, '', 60001, 1, 2, '今日の運勢は中吉！\u3000旅行運がぐんぐんと上昇中♪\u3000\u3000\u3000\u3000\u3000\u3000\u3000もしかしたら、あの「マホマホ王国」にだって行けるかも♪', 0);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (105, 0, 3, '', 0, 0, '', 60001, 1, 2, '今日の運勢は中吉！\u3000仕事運が急上昇中です！\u3000\u3000\u3000\u3000\u3000\u3000\u3000\u3000\u3000きっと「煉獄に舞う一陣の疾風」の如き活躍ができますよ！', 0);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (106, 0, 3, '', 0, 0, '', 60001, 1, 2, '今日の運勢は中吉！\u3000チャンスを待つと良い結果に！\u3000\u3000\u3000\u3000\u3000\u3000ラッキーアイテムのプリンを食べて、運を呼び込みましょう！', 0);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (107, 0, 3, '', 0, 0, '', 60001, 1, 2, '今日の運勢は中吉！\u3000お出かけした先で良縁に恵まれそうです！\u3000ダウナー系あざとい女子が、あま～い飴をくれるかも？', 0);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (108, 0, 3, '', 0, 0, '', 60001, 1, 2, '今日の運勢は中吉！\u3000大抵のことはゴリ押しでなんとかできます！ラッキープレイスはゲーセン。パンチングマシンでストレス発散！', 0);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (109, 0, 3, '', 0, 0, '', 60001, 2, 2, '今日の運勢は中吉！\u3000運気が着々と上昇中！\u3000\u3000\u3000\u3000\u3000\u3000\u3000\u3000\u3000\u3000精霊の加護を受けたかの如く、色々な事がうまくいきますよ♪', 0);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (110, 0, 4, '', 0, 0, '', 60001, 1, 2, '今日の運勢は小吉！\u3000早朝に幸運の兆しあり！\u3000\u3000\u3000\u3000\u3000\u3000\u3000\u3000\u3000もしかしたら、優しいお姉ちゃんが起こしにきてくれますよ♪', 0);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (111, 0, 4, '', 0, 0, '', 60001, 1, 2, '今日の運勢は小吉！\u3000運気上昇中ですが、上がるまでが要注意！\u3000ラッキーアニマルは熊！\u3000本当の家族のように守ってくれるかも♪', 0);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (112, 0, 4, '', 0, 0, '', 60001, 1, 2, '今日の運勢は小吉！\u3000外に出てゆっくり過ごすと運気が上昇！\u3000\u3000ラッキースポットは牧場。面白い出会いがありそうです♪', 0);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (113, 0, 4, '', 0, 0, '', 60001, 1, 2, '今日の運勢は小吉！\u3000運気は高いけども、ハプニングには注意！\u3000出かけた先で、「ふしんしゃ」扱いされてしまうかも……', 0);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (114, 0, 4, '', 0, 0, '', 60001, 1, 2, '今日の運勢は小吉！\u3000同腹一心の友だちが見つかるかも！\u3000\u3000\u3000\u3000キーワードは「ユニちゃんズ」、記憶に刻みましょう！', 0);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (115, 0, 4, '', 0, 0, '', 60001, 1, 2, '今日の運勢は小吉！\u3000思わぬ相手と仲良くなれるかも？\u3000\u3000\u3000\u3000\u3000うっかり毒舌をもらしてしまわないように要注意です！', 0);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (116, 0, 4, '', 0, 0, '', 60001, 2, 2, '今日の運勢は小吉！\u3000根を詰めずにリラックスすると運気向上！\u3000ラッキーパーソンはアイドル。歌があなたを幸せにしてくれます♪', 0);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (117, 2, 0, '', 112101, 0, 'スズメ', 60001, 0, 3, 'おみくじの結果はいかがでしたか？\\n新たに始まる一日が、\\nあなたにとってよい日になりますように\\n明日もお待ちしていますね♪', 0);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (118, 3, 0, '', 112101, 7, 'スズメ', 60001, 0, 3, 'おみくじ、楽しんで頂けましたか？\\nあなたの新しい年が\\n素晴らしいものになるよう、\\n心からお祈りしますね', 0);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (119, 1, 0, '', 105801, 1, 'ペコリーヌ', 80003, 0, 0, 'ヒューヒュー♪\\nドンドンパフパフー♪', 0);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (120, 1, 0, '', 105901, 1, 'コッコロ', 80003, 0, 1, 'ひゅーひゅー\\nどんどんぱふぱふー\\nでございます', 0);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (121, 2, 0, '', 105901, 1, 'コッコロ', 80003, 0, 1, 'さぁ、キャルさまもご一緒に\\nどんどんぱふぱふいたしましょう', 0);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (122, 1, 0, '', 106001, 1, 'キャル', 80003, 0, 2, 'え？\u3000ちょっと\\nいきなりなにっ？', 0);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (123, 2, 0, '', 106001, 1, 'キャル', 80003, 0, 2, 'ドンドンパフパフってなんなの？\\nあたしにも分かるように\\nちゃんと説明しなさいっての！', 0);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (124, 2, 0, '', 105801, 1, 'ペコリーヌ', 80003, 0, 0, '実はですねキャルちゃん！\\nもうすぐわたしたちにとっての\\n大切な節目──', 0);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (125, 3, 0, '', 105801, 1, 'ペコリーヌ', 80003, 0, 0, '『プリンセスコネクト！\\nRe:Dive』\\n2.5周年なんですよ！\\nやばいですね☆', 0);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (126, 3, 0, '', 105901, 1, 'コッコロ', 80003, 0, 1, 'ですからその日に向けて\\n今から気分を盛り上げているのです', 0);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (127, 3, 0, '', 106001, 1, 'キャル', 80003, 0, 2, 'ああ、そういえば\\nそんな時期だっけ\\nって言っても、もう少し先じゃない\\n気が早いんじゃないの？', 0);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (128, 4, 0, '', 105901, 1, 'コッコロ', 80003, 0, 1, 'いいえ、キャルさま\\nこういったお祝いは準備から\\n楽しむものでございます\\nそうですよね、ペコリーヌさま', 0);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (129, 4, 0, '', 105801, 1, 'ペコリーヌ', 80003, 0, 0, 'その通りです♪\u3000というわけで！\\nカウントダウンの始まりですよ！\\nみんなで一緒に2.5周年に向けて\\n盛り上がっていきましょー☆', 0);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (130, 4, 0, '', 106001, 1, 'キャル', 80003, 0, 2, 'ド、ドンドンパフパフ～\\nって何言わせんのよ！\\nまったくもう、浮かれちゃってさ', 0);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (131, 5, 0, '', 105901, 1, 'コッコロ', 80003, 0, 1, 'ふふ。キャルさまもワクワクして\\nおいでのようですね\\nそれでは主さま。大切な記念日まで\\nどうぞご期待くださいませ', 0);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (132, 5, 0, '', 106001, 2, 'キャル', 80003, 0, 0, '記念日を盛り上げるったって\\n一体どうしたらいいのよ？\\nあたし、そういうの\\n苦手なんだけど…', 0);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (133, 1, 0, '', 190801, 2, 'カリン', 80003, 0, 1, 'あら、キャルさん\\nどうかなさいましたか？\\n何かお困りのようですけど', 0);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (134, 6, 0, '', 106001, 2, 'キャル', 80003, 0, 0, 'げっ…カリンじゃない\\nなんでもないわよ！', 0);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (135, 2, 0, '', 190801, 2, 'カリン', 80003, 0, 1, 'そうなのですか？\\nキャルさんのことですからてっきり\\n2.5周年をどう盛り上げたら\\nいいか悩んでいるのかと…', 0);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (136, 7, 0, '', 106001, 2, 'キャル', 80003, 0, 0, '分かってんじゃないのよ！？\\nいっ、いや、違うけどね！\\nあたしは別にそんなことで\\n悩んでないわよっ？', 0);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (137, 3, 0, '', 190801, 2, 'カリン', 80003, 0, 1, 'ふふっ…\\nこういう時は、真心を込めて\\n気持ちをそのまま口にしたら\\nいいのではないでしょうか？', 0);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (138, 8, 0, '', 106001, 2, 'キャル', 80003, 0, 0, '気持ちを、ねぇ\\nそれが一番難しいんじゃない…\\nそもそも、あたしは記念日とか\\n別にどうだっていいし', 0);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (139, 9, 0, '', 106001, 2, 'キャル', 80003, 0, 0, '…まあ、ペコリーヌもコロ助も\\nやけに楽しそうだったから…\\nこういうお祭り騒ぎみたいなのも\\nたまにはいいかな、とは思うけど', 0);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (140, 4, 0, '', 190801, 2, 'カリン', 80003, 0, 1, 'なるほどなるほど～\\nキャルさんは【美食殿】で祝う\\n2.5周年を心から楽しみに\\nしている、ということですね！', 0);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (141, 10, 0, '', 106001, 2, 'キャル', 80003, 0, 0, 'はぁ！？\\nどこ聞いたらそうなるのよ！\\nあたしは別に楽しみになんか…！', 0);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (142, 5, 0, '', 190801, 2, 'カリン', 80003, 0, 1, 'キャルさんの心からの想い\\nみなさんにも伝わったでしょうか？\\n私も2.5周年が楽しみです！\\n以上、カリンがお伝えしました！', 0);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (143, 11, 0, '', 106001, 2, 'キャル', 80003, 0, 0, '心からの想いって何なのよ！？\\n勝手に人の言葉を\\n捻じ曲げんじゃないわよ！\\nこのくそ眼鏡ーーーっ！', 0);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (144, 6, 0, '', 105901, 3, 'コッコロ', 80003, 0, 0, 'ペコリーヌさま、もうすぐ\\n記念日でございますね\\nこういった節目というのは\\n感慨深いものでございます', 0);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (145, 5, 0, '', 105801, 3, 'ペコリーヌ', 80003, 0, 1, '色んな思い出が蘇ってきますね！\\n楽しい出来事が\\nいっぱいありました♪', 0);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (146, 7, 0, '', 105901, 3, 'コッコロ', 80003, 0, 0, 'はい、そうでございますね\\n主さまも【美食殿】の活動の他にも\\nいろんなご経験をされたと\\n聞いておりますよ', 0);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (147, 8, 0, '', 105901, 3, 'コッコロ', 80003, 0, 0, 'たしか…ランドソルで話題沸騰と\\nなっていた、魔法少女なるものに\\nお会いになられたとか', 0);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (148, 6, 0, '', 105801, 3, 'ペコリーヌ', 80003, 0, 1, '魔法少女って、あの美味しくって\\n栄養たっぷりの大ヒット商品\\n『魔法少女ソーセージ』の箱に\\n描いてある女の子のことですか！？', 0);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (149, 7, 0, '', 105801, 3, 'ペコリーヌ', 80003, 0, 1, 'あのソーセージ\\n美味しいんですよね～♪\\nわたしもたっくさん食べてますよ！', 0);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (150, 9, 0, '', 105901, 3, 'コッコロ', 80003, 0, 0, 'あとは、牧場に素敵な温泉が\\n出来たとか…', 0);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (151, 8, 0, '', 105801, 3, 'ペコリーヌ', 80003, 0, 1, '牧場ですか！？\u3000温泉につかって\\nチーズもオツですね～♪\u3000考えた\\nだけでよだれが出ちゃいそうです！\\nやばいですね☆', 0);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (152, 10, 0, '', 105901, 3, 'コッコロ', 80003, 0, 0, 'ペコリーヌさま\\n言ってるそばからよだれが…\\n今お拭きしますね。ふき、ふき', 0);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (153, 9, 0, '', 105801, 3, 'ペコリーヌ', 80003, 0, 1, 'えへへ、ありがとうございます\\nコッコロちゃん！', 0);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (154, 11, 0, '', 105901, 3, 'コッコロ', 80003, 0, 0, 'それにしても、主さまは\\n【美食殿】の一員として様々な\\n美食と出会われていたのですね\\nわたくし、感服いたしました', 0);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (155, 10, 0, '', 105801, 3, 'ペコリーヌ', 80003, 0, 1, 'これからもたくさん冒険をして\\nめいっぱい美食を\\n味わい尽くしましょうね！', 0);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (156, 11, 0, '', 105801, 4, 'ペコリーヌ', 80003, 0, 0, '2.5周年カウントダウン♪\\nキャルちゃんキャルちゃん！\\nわくわくしますね☆', 0);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (157, 12, 0, '', 106001, 4, 'キャル', 80003, 0, 1, 'あぁもう、うるさいわね～\\nまだまだ先でしょ？\\nちょっとは落ち着きなさいよ', 0);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (158, 12, 0, '', 105801, 4, 'ペコリーヌ', 80003, 0, 0, 'キャルちゃんだって最近\\nソワソワしてるじゃないですか～\\nさっきもご機嫌そうに鼻歌とか\\n歌ってましたよね？', 0);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (159, 13, 0, '', 106001, 4, 'キャル', 80003, 0, 1, 'なっ…！\u3000き、聞いてたの！？\\nじゃない、歌ってないわよ！？\\nあんたいい加減なこと言うと\\nぶっ殺すわよ！？', 0);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (160, 13, 0, '', 105801, 4, 'ペコリーヌ', 80003, 0, 0, 'えっへへ～♪\\nわたしは最近のキャルちゃんが\\nもっともっと大好きですよ♪\\nすごく積極的になりましたよね！', 0);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (161, 14, 0, '', 106001, 4, 'キャル', 80003, 0, 1, '…積極的？\\nなんの話よ？', 0);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (162, 14, 0, '', 105801, 4, 'ペコリーヌ', 80003, 0, 0, 'またまた～♪\\nアイドルを目指そうとしたこと\\n忘れちゃったんですか？', 0);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (163, 15, 0, '', 105801, 4, 'ペコリーヌ', 80003, 0, 0, 'ムーサの町で\\nきゃるきゃる～ん☆\u3000って！', 0);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (164, 15, 0, '', 106001, 4, 'キャル', 80003, 0, 1, 'あっ…！？\u3000ちちち違うわよっ！\\nあれは操られてただけで\\nあたしはアイドルなんか\\n目指してないっての！！', 0);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (165, 16, 0, '', 105801, 4, 'ペコリーヌ', 80003, 0, 0, '本当に本当ですか？\\nわたし、キャルちゃんとっても\\n乗り気だなって\\n思ってたんですけど～', 0);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (166, 16, 0, '', 106001, 4, 'キャル', 80003, 0, 1, 'まぁ、悪くはなかったけど…って\\nだ、だから目指してないって\\n言ってるでしょ！！\\nなんてこと思い出させんのよ！？', 0);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (167, 17, 0, '', 106001, 4, 'キャル', 80003, 0, 1, 'ああ…ダメだわ…\\nもう殺すしかない…\\n2.5周年が来る前に\\n記憶ごと消し去ってやるー！', 0);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (168, 18, 0, '', 106001, 5, 'キャル', 80003, 0, 0, '2.5周年まであと10日…\\nふ～ん？\\n案外早いもんね？', 0);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (169, 12, 0, '', 105901, 5, 'コッコロ', 80003, 0, 1, 'そうでございますね…\\nその日のためにやるべきことは\\nまだまだございます\\n気を引き締めねばなりません…！', 0);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (170, 19, 0, '', 106001, 5, 'キャル', 80003, 0, 0, 'やる気十分ねコロ助…\\nそんな気負ってるとしんどいわよ？\\nお気楽にやりましょ？', 0);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (171, 13, 0, '', 105901, 5, 'コッコロ', 80003, 0, 1, 'キャルさま…\\nありがとうございます\\nキャルさまは本当に\\n優しいおかたです', 0);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (172, 20, 0, '', 106001, 5, 'キャル', 80003, 0, 0, 'な、なにわけの分かんないこと\\n言ってんのよ…\\nあたしは優しくなんかないっての', 0);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (173, 14, 0, '', 105901, 5, 'コッコロ', 80003, 0, 1, 'そんなことはございません\\n…あの、実はわたくし\\nキャルさまに\\nひとつお願いがございまして', 0);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (174, 21, 0, '', 106001, 5, 'キャル', 80003, 0, 0, 'お願い？\u3000珍しいわね\\nコロ助がそんなこと言うなんて\\n…まあ、あたしに出来ることなら\\n別にいいけど', 0);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (175, 15, 0, '', 105901, 5, 'コッコロ', 80003, 0, 1, 'ありがとうございます\\n実は記念日へ向けて\\n『かくし芸』というものを\\n用意してみようかと思いまして', 0);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (176, 22, 0, '', 106001, 5, 'キャル', 80003, 0, 0, 'かくし芸？', 0);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (177, 16, 0, '', 105901, 5, 'コッコロ', 80003, 0, 1, 'はい。きゃるきゃる～ん☆\u3000を\\n参考に、ころころ～ん☆\u3000という\\nご挨拶を考えてみたのですが\\nポーズがうまくいかなくて…', 0);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (178, 23, 0, '', 106001, 5, 'キャル', 80003, 0, 0, '～～！！\u3000ちょっと褒められて\\nいい気になって損したわ！！\\nふざけんなふざけんな\\nふ～ざ～け～ん～な～っ！！', 0);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (179, 17, 0, '', 105801, 6, 'ペコリーヌ', 80003, 0, 0, 'あと９日！\u3000もうすぐですよ♪\\nえへへ、楽しみで楽しみで\\nごはんが進みますね☆', 0);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (180, 24, 0, '', 106001, 6, 'キャル', 80003, 0, 2, 'ごはんが進みますね☆\\nじゃなーい！\\nいくらなんでも食べ過ぎよ！\\n記念日、迎えられなくなるわよ！？', 0);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (181, 17, 0, '', 105901, 6, 'コッコロ', 80003, 0, 1, '大丈夫ですよキャルさま\\n食事はわたくしたちの\\n歩んできた道そのもの\\nなのですから', 0);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (182, 18, 0, '', 105801, 6, 'ペコリーヌ', 80003, 0, 0, 'さっすがコッコロちゃん\\nいいことを言いますね！\\nそう、わたしたち\\n【美食殿】の活動目的は─', 0);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (183, 25, 0, '', 106001, 6, 'キャル', 80003, 0, 2, '─みんなで楽しく食事をすること\\nでしょ？\\nあれだけ食べ歩いてきたんだから\\n分かってるわよ', 0);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (184, 18, 0, '', 105901, 6, 'コッコロ', 80003, 0, 1, 'はい…そうでございますね♪\\nそれにしてもわたくしたち\\n本当にいろいろなものを\\n食べ歩いてきましたね…', 0);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (185, 26, 0, '', 106001, 6, 'キャル', 80003, 0, 2, 'そうね…ほんっとうにね…\\n毒まみれのニセドラゴンとか\\n恐竜…は逃げられちゃったっけ\\nあとワニゴ…ワニの魔物とかね', 0);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (186, 27, 0, '', 106001, 6, 'キャル', 80003, 0, 2, 'そして、とうとう本物の\\nドラゴンまで相手に\\nしちゃったのよね、あたしたちって', 0);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (187, 28, 0, '', 106001, 6, 'キャル', 80003, 0, 2, '信じられない強さだったわね\\nあのドラゴン…やっぱり\\n作戦はしっかり立てていかないと\\nダメよね', 0);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (188, 19, 0, '', 105801, 6, 'ペコリーヌ', 80003, 0, 0, 'えへへ…☆\\nキャルちゃんが色んなことを\\n覚えていてくれて\\nうれしいです♪', 0);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (189, 19, 0, '', 105901, 6, 'コッコロ', 80003, 0, 1, 'わたくしも鮮明に覚えておりますよ\\n主さまもきっと…♪', 0);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (190, 29, 0, '', 106001, 6, 'キャル', 80003, 0, 2, 'あったり前でしょ！\\n忘れないわよ、あんな滅茶苦茶な\\nものばかり食べさせられて！\\n…忘れられるわけ、ないじゃない', 0);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (191, 30, 0, '', 106001, 7, 'キャル', 80003, 0, 0, 'ねえちょっと、ちょっと待って！？\\nカリンから、2.5周年記念の\\n生放送に出演してほしいって\\n言われたんだけど！', 0);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (192, 31, 0, '', 106001, 7, 'キャル', 80003, 0, 0, 'なんでそういう大事なことを\\n急に言うわけ！？\\nそんなの聞いてないわよ～！？', 0);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (193, 32, 0, '', 106001, 7, 'キャル', 80003, 0, 0, 'いっぱい人に見られちゃうのよね？\\nなんであたしがそんなこと…', 0);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (194, 33, 0, '', 106001, 7, 'キャル', 80003, 0, 0, 'あー\\nあー\\n…声、これで大丈夫かしら？', 0);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (195, 34, 0, '', 106001, 7, 'キャル', 80003, 0, 0, '聞き取りにくいかもしれないわね…\\nもうちょっと明るい方がいいかも\\nえっと…こんな感じ？', 0);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (196, 35, 0, '', 106001, 7, 'キャル', 80003, 0, 0, 'オイッスー☆', 0);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (197, 36, 0, '', 106001, 7, 'キャル', 80003, 0, 0, '……\\nいや、ないわ\\nいつもどおりが一番ね、うん', 0);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (198, 37, 0, '', 106001, 7, 'キャル', 80003, 0, 0, 'もう、記念の生放送なんて\\n超責任重大なやつじゃない…\\nもしなにか失敗とかしたら…', 0);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (199, 38, 0, '', 106001, 7, 'キャル', 80003, 0, 0, 'ど、どど、どうしよう！？\\n緊張してきちゃった…！！', 0);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (200, 20, 0, '', 105901, 8, 'コッコロ', 80003, 0, 0, '主さま、わたくし\\nペコリーヌさまとキャルさまと共に\\n2.5周年を祝う生放送に\\n出演する大役を仰せつかりました', 0);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (201, 21, 0, '', 105901, 8, 'コッコロ', 80003, 0, 0, '多くの方々に\\n『プリンセスコネクト！\\nRe:Dive』の魅力をお伝えする\\n重要な役割でございます', 0);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (202, 22, 0, '', 105901, 8, 'コッコロ', 80003, 0, 0, 'わたくし、全身全霊をもって\\n生放送に取り組みたいと\\n思っております', 0);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (203, 23, 0, '', 105901, 8, 'コッコロ', 80003, 0, 0, 'ですが、もしかしたら\\nセリフを噛んでしまったり\\n段取りを間違えてしまったり\\nするかもしれません…', 0);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (204, 24, 0, '', 105901, 8, 'コッコロ', 80003, 0, 0, 'そのようなことがないよう\\n練習はしっかりしておかなくては\\nまずはこちらから…', 0);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (205, 25, 0, '', 105901, 8, 'コッコロ', 80003, 0, 0, 'オイッスー☆', 0);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (206, 26, 0, '', 105901, 8, 'コッコロ', 80003, 0, 0, '先ほどキャルさまが練習されて\\nいるのをお見かけしたので\\nわたくしもと思いまして…\\nいかがでしょうか？', 0);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (207, 27, 0, '', 105901, 8, 'コッコロ', 80003, 0, 0, '良い感じ、ですか？\\n…ふふ、ありがとうございます\\n主さまのあたたかいお言葉があれば\\nわたくしは百人力でございます', 0);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (208, 28, 0, '', 105901, 8, 'コッコロ', 80003, 0, 0, 'この大役を無事に成し遂げ\\n主さまに素敵な2.5周年を\\n迎えていただけるよう…\\nわたくし、尽力いたしますね', 0);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (209, 20, 0, '', 105801, 9, 'ペコリーヌ', 80003, 0, 0, 'オイッスー☆', 0);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (210, 21, 0, '', 105801, 9, 'ペコリーヌ', 80003, 0, 0, '…う～ん、今のはちょっと\\n違う感じがしますね\\n堅苦しかったかもしれません', 0);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (211, 22, 0, '', 105801, 9, 'ペコリーヌ', 80003, 0, 0, 'あと６日で2.5周年ですか…', 0);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (212, 23, 0, '', 105801, 9, 'ペコリーヌ', 80003, 0, 0, 'この年月がオイッスーの\\n歴史なんだと思うと\\nじ～んとしちゃいます！\\nやばいですね☆', 0);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (213, 24, 0, '', 105801, 9, 'ペコリーヌ', 80003, 0, 0, '生放送で最高のオイッスー☆\u3000を\\nみなさんにお届けするために\\n頑張らないと！\\nそれじゃあもう一度…', 0);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (214, 25, 0, '', 105801, 9, 'ペコリーヌ', 80003, 0, 0, 'オイッスー☆', 0);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (215, 26, 0, '', 105801, 9, 'ペコリーヌ', 80003, 0, 0, '…うう～ん、どうしてでしょう\\nまだ何かが違う気がします…\\nもしかしたら\\nおなかが空きすぎてるとか？', 0);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (216, 27, 0, '', 105801, 9, 'ペコリーヌ', 80003, 0, 0, '今さっき食べたばっかりですけど\\nおなかが減っては\\n良いオイッスー☆\u3000は\\n出せませんよね！', 0);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (217, 28, 0, '', 105801, 9, 'ペコリーヌ', 80003, 0, 0, 'そうと決まれば、コッコロちゃんと\\nキャルちゃんを誘って\\nごはんにしましょう！\\n善は急げです！', 0);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (218, 29, 0, '', 105801, 9, 'ペコリーヌ', 80003, 0, 0, 'あ、二人が丁度いいところに！\\nオイッス～☆\u3000…ああ！！\\n今の、今のですよ～♪', 0);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (219, 30, 0, '', 105801, 9, 'ペコリーヌ', 80003, 0, 0, 'なるほど、どんな時も\\n自然体が一番ってことですね！\\nこの調子で、生放送も\\n頑張っちゃいます♪', 0);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (220, 31, 0, '', 105801, 10, 'ペコリーヌ', 80003, 0, 0, '2.5周年まで残り５日ですが\\nその前にもうすぐ生放送ですよ！\\nコッコロちゃん\\n準備の方はどうですか？', 0);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (221, 29, 0, '', 105901, 10, 'コッコロ', 80003, 0, 1, 'はい。わたくし、しっかりと\\n備えてまいりました\\n万事抜かりはございません', 0);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (222, 32, 0, '', 105801, 10, 'ペコリーヌ', 80003, 0, 0, 'おお～すごい自信を感じます…！\\nいい生放送になりそうですね☆\\n……あれ？\u3000なんだかこの辺り\\n揺れていませんか？', 0);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (223, 39, 0, '', 106001, 10, 'キャル', 80003, 0, 2, '…………', 0);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (224, 30, 0, '', 105901, 10, 'コッコロ', 80003, 0, 1, 'キャルさま？\\nお風邪をひかれたんでしょうか\\nひどい震えですが…', 0);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (225, 40, 0, '', 106001, 10, 'キャル', 80003, 0, 2, 'かかかか風邪じゃないわよ！\\nここここれはただ\\nななな生放送が楽しみ過ぎて\\nワワワワクワクが止まらないだけ！', 0);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (226, 33, 0, '', 105801, 10, 'ペコリーヌ', 80003, 0, 0, '大丈夫ですかキャルちゃん！？\\nそうだ、これを飲んでください！', 0);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (227, 41, 0, '', 106001, 10, 'キャル', 80003, 0, 2, 'きき気がきくじゃない、ありがとっ\\nごくっ、んく…ぶはぁっ！？\\nちょっと何飲ませたの！？\\n辛っ！\u3000苦ぁ！？\u3000甘ぁっ！？', 0);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (228, 34, 0, '', 105801, 10, 'ペコリーヌ', 80003, 0, 0, 'これは魔物のエキスに薬草に\\nその他色んなものを混ぜた\\n特製の栄養ドリンクです！', 0);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (229, 35, 0, '', 105801, 10, 'ペコリーヌ', 80003, 0, 0, 'これを飲めば体ぽかぽかで\\n元気いっぱいですよ♪', 0);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (230, 42, 0, '', 106001, 10, 'キャル', 80003, 0, 2, 'このアホリーヌ！\\n風邪じゃないって言ったでしょ！？\\nどさくさに紛れて\\nそんな恐ろしいもん飲ませんな～！', 0);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (231, 31, 0, '', 105901, 10, 'コッコロ', 80003, 0, 1, 'キャルさま\\n震えが収まっておりますね\\nよかったです…\\nわたくし、心配いたしました', 0);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (232, 43, 0, '', 106001, 10, 'キャル', 80003, 0, 2, 'え？\u3000ああ、ホントね…って\\nだから風邪じゃないって\\n言ってるのに…\\nまあいいわこの際なんでも', 0);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (233, 36, 0, '', 105801, 10, 'ペコリーヌ', 80003, 0, 0, 'えっへへ～♪\u3000いつも通りの\\nキャルちゃんに戻りましたし\\n素敵な生放送が出来そうですね！\\n今から楽しみです☆', 0);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (234, 6, 0, '', 190801, 11, 'カリン', 80003, 0, 0, 'ランドソルのみなさま、こんにちは\\n生放送の会場設営を担当しています\\n【ギルド管理協会】のカリンです', 0);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (235, 7, 0, '', 190801, 11, 'カリン', 80003, 0, 0, '【美食殿】のみなさんは\\nまもなく始まる生放送に向けて\\n最後の調整のため\\n席を外しています', 0);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (236, 8, 0, '', 190801, 11, 'カリン', 80003, 0, 0, '頑張っている３人の\\n邪魔をするわけには\\nいきませんので、ご容赦ください', 0);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (237, 9, 0, '', 190801, 11, 'カリン', 80003, 0, 0, 'ですので、本日は私から\\n【美食殿】のみなさんの様子を\\nお伝えさせていただこうと思います', 0);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (238, 10, 0, '', 190801, 11, 'カリン', 80003, 0, 0, 'まずはペコリーヌさんですが…\\n何やら大量のおにぎりを\\n食べているようです\\nえっと…栄養は大事ですよね', 0);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (239, 11, 0, '', 190801, 11, 'カリン', 80003, 0, 0, '次にコッコロさんですが\\nこちらは発声練習をしています', 0);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (240, 12, 0, '', 190801, 11, 'カリン', 80003, 0, 0, '一生懸命、小さなお口を開けて\\n声を出す姿が応援したくなりますね', 0);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (241, 13, 0, '', 190801, 11, 'カリン', 80003, 0, 0, 'そしてキャルさんは…\\nこれは…堂々としたものですね\\n何もせず、ただ立ち尽くして…', 0);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (242, 14, 0, '', 190801, 11, 'カリン', 80003, 0, 0, 'あれ？\\nもしかして緊張で気を失って…？', 0);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (243, 15, 0, '', 190801, 11, 'カリン', 80003, 0, 0, '…ええと\\n【美食殿】のみなさんは\\nやる気十分なようですね！', 0);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (244, 16, 0, '', 190801, 11, 'カリン', 80003, 0, 0, '３人とも生放送を\\nいいものにしようと\\n全力で頑張ってくれていますので\\nどうかご期待ください', 0);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (245, 17, 0, '', 190801, 11, 'カリン', 80003, 0, 0, 'それでは\\nまた明日お会いしましょう♪', 0);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (246, 44, 0, '', 106001, 12, 'キャル', 80003, 0, 0, '2.5周年まであと３日！\\nそして生放送は明日！\\nなんかいよいよって感じね…', 0);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (247, 37, 0, '', 105801, 12, 'ペコリーヌ', 80003, 0, 2, '３人でい～っぱい練習しましたし\\nきっと大丈夫ですよ☆', 0);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (248, 32, 0, '', 105901, 12, 'コッコロ', 80003, 0, 1, 'ペコリーヌさまに\\n大丈夫と言ってもらえると\\nとても心強いですね', 0);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (249, 45, 0, '', 106001, 12, 'キャル', 80003, 0, 0, '信じすぎちゃだめよコロ助\\nこいつはなーんにも\\n考えてないだけなんだから', 0);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (250, 38, 0, '', 105801, 12, 'ペコリーヌ', 80003, 0, 2, 'ひどいですよぉキャルちゃ～ん！', 0);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (251, 33, 0, '', 105901, 12, 'コッコロ', 80003, 0, 1, 'ふふ。お二人とも\\n普段通りの様子で\\n安心いたしました', 0);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (252, 39, 0, '', 105801, 12, 'ペコリーヌ', 80003, 0, 2, 'はいっ☆\\n生放送でもなんでも\\n全力全開、わたしらしく\\nぶつかっていくだけです！', 0);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (253, 46, 0, '', 106001, 12, 'キャル', 80003, 0, 0, 'そうね。おめでたいことなんだし\\nここまで来たんなら\\n楽しめるだけ\\n楽しむしかないわよね！', 0);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (254, 34, 0, '', 105901, 12, 'コッコロ', 80003, 0, 1, 'わたくしも、普段よりも心が\\n熱くなっております\\nこの胸の気持ちをお伝えできるよう\\n精一杯努力いたします…！', 0);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (255, 40, 0, '', 105801, 12, 'ペコリーヌ', 80003, 0, 2, 'それでは、いきましょう！\\n明日の生放送、絶対に\\n成功させましょうね☆', 0);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (256, 41, 0, '', 105801, 13, 'ペコリーヌ', 80003, 0, 0, 'えっと、最初のひと言は…あれ？\\nキャルちゃん、わたし\\n何て言うんでしたっけ？', 0);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (257, 47, 0, '', 106001, 13, 'キャル', 80003, 0, 2, 'は！？\\nなにいきなりど忘れしてるの！？\\nっていうかあんた、台本は！？', 0);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (258, 42, 0, '', 105801, 13, 'ペコリーヌ', 80003, 0, 0, '忘れてきちゃいました☆', 0);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (259, 48, 0, '', 106001, 13, 'キャル', 80003, 0, 2, '忘れてきちゃいました☆\\nで済ませられると思ってんの！？\\nほら、あたし二冊持ってきたから\\nこれ使いなさい！', 0);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (260, 35, 0, '', 105901, 13, 'コッコロ', 80003, 0, 1, 'マイクとは、こんな高い位置に\\nあるものなのですね…！\\n背伸びをすれば、何とか…\\nう～ん、うぅ～ん…！', 0);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (261, 49, 0, '', 106001, 13, 'キャル', 80003, 0, 2, 'あぁもう\\n少し下げればいいでしょ！？\\nこれくらいでいい？\\nまったく、世話が焼けるわね…', 0);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (262, 43, 0, '', 105801, 13, 'ペコリーヌ', 80003, 0, 0, 'あれ？\\nキャルちゃん、後ろ髪が\\nはねちゃってますよ？', 0);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (263, 50, 0, '', 106001, 13, 'キャル', 80003, 0, 2, 'え？\u3000うそっ！？\\nちゃんと確かめてきたのに！\\nどこどこ！？', 0);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (264, 36, 0, '', 105901, 13, 'コッコロ', 80003, 0, 1, 'キャルさま、動かないで\\nくださいまし。今くしで…\\nはい、直りましたよ', 0);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (265, 51, 0, '', 106001, 13, 'キャル', 80003, 0, 2, 'あ、ありがと…はぁ。生放送\\n本番までもうすぐなのに\\nこんなことしてる場合じゃ\\nないわよね', 0);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (266, 37, 0, '', 105901, 13, 'コッコロ', 80003, 0, 1, 'はい、時間は残りわずかです\\nですが、慌ただしく\\n動き回るこの時間も\\nなんだか楽しくて…♪', 0);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (267, 52, 0, '', 106001, 13, 'キャル', 80003, 0, 2, 'コロ助、あんた…って\\nそうじゃなくて！\\n胸にジンワリきてる\\n暇なんかないでしょ…！？', 0);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (268, 44, 0, '', 105801, 13, 'ペコリーヌ', 80003, 0, 0, 'あはは♪\\nキャルちゃんの動きが\\nとっても面白いです♪\\nやばいですね☆', 0);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (269, 38, 0, '', 105901, 13, 'コッコロ', 80003, 0, 1, 'ふふ\\nきっと面白い生放送になると\\nわたくし、確信しております', 0);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (270, 45, 0, '', 105801, 13, 'ペコリーヌ', 80003, 0, 0, '絶対絶対、間違いありません！\\n見てくれるみなさんが\\n笑顔になれる時間を\\nお届けしましょう！', 0);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (271, 53, 0, '', 106001, 13, 'キャル', 80003, 0, 2, 'そんなの当然でしょ！\\n誰が見たって面白いって\\n言ってもらえるように\\nあれだけ準備したんだから！', 0);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (272, 46, 0, '', 105801, 13, 'ペコリーヌ', 80003, 0, 0, 'それでは\\n記念日直前生放送！\\n楽しみにしててくださいね☆', 0);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (273, 18, 0, '', 190801, 14, 'カリン', 80003, 0, 0, 'こんにちは\\n【ギルド管理協会】のカリンです', 0);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (274, 19, 0, '', 190801, 14, 'カリン', 80003, 0, 0, '昨日の生放送は\\nいかがだったでしょうか？', 0);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (275, 20, 0, '', 190801, 14, 'カリン', 80003, 0, 0, 'たくさんの笑顔と喜びと\\nそして驚きを受け取って\\nいただけたのではないかと思います', 0);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (276, 21, 0, '', 190801, 14, 'カリン', 80003, 0, 0, 'そしていよいよ\\n明日は2.5周年の当日\\n待ちに待った記念日を\\n迎えることとなります', 0);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (277, 22, 0, '', 190801, 14, 'カリン', 80003, 0, 0, '【美食殿】のみなさんも\\n張り切って様々な準備を\\nされていますよ', 0);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (278, 23, 0, '', 190801, 14, 'カリン', 80003, 0, 0, '【ギルド管理協会】も\\n万全のサポート体制で\\n協力してまいりたいと思います', 0);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (279, 24, 0, '', 190801, 14, 'カリン', 80003, 0, 0, '…ふふ、本当に楽しみですね\\n【ギルド管理協会】の職員として\\nだけではなく、私個人としても…', 0);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (280, 25, 0, '', 190801, 14, 'カリン', 80003, 0, 0, 'この記念日を迎えられることが\\n心から楽しみですし\\n幸せを感じています', 0);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (281, 26, 0, '', 190801, 14, 'カリン', 80003, 0, 0, 'きっと【美食殿】のみなさんは\\nそれ以上に心を弾ませて\\nいることでしょう', 0);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (282, 27, 0, '', 190801, 14, 'カリン', 80003, 0, 0, 'それでは\\n明日からの2.5周年を\\nどうぞ、お楽しみに…♪', 0);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (283, 47, 0, '', 105801, 15, 'ペコリーヌ', 80003, 0, 0, '準備はいいですかっ？\\n…いっきますよー！', 0);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (284, 54, 0, '', 106001, 15, 'キャル', 80003, 0, 2, '祝！', 0);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (285, 39, 0, '', 105901, 15, 'コッコロ', 80003, 0, 1, '2.5周年！', 0);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (286, 48, 0, '', 105801, 15, 'ペコリーヌ', 80003, 0, 0, 'おめでとうございま～す☆', 0);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (287, 55, 0, '', 106001, 15, 'キャル', 80003, 0, 2, '少し前まではまだまだ先じゃない\\nとか言ってたけど\\n本当にあっという間だったわね', 0);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (288, 40, 0, '', 105901, 15, 'コッコロ', 80003, 0, 1, '光陰矢の如し…\\nとはこのことでございますね\\nでも、今日という日を無事に\\n迎えることができて良かったです', 0);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (289, 49, 0, '', 105801, 15, 'ペコリーヌ', 80003, 0, 0, 'コッコロちゃん！\u3000キャルちゃん！\\n落ち着くには\\nまだ早いですよ！\\n盛り上がるのはこれからです☆', 0);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (290, 56, 0, '', 106001, 15, 'キャル', 80003, 0, 2, 'ほんとあんたはいつも\\n全力全開ねー\\nでもそうね、記念日なんだし\\nパーっといきましょ！', 0);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (291, 41, 0, '', 105901, 15, 'コッコロ', 80003, 0, 1, 'ええ、わたくしも全力全開で\\nまいります…！\\n主さま、さあ\\nどうぞ手を取ってくださいまし…♪', 0);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (292, 57, 0, '', 106001, 15, 'キャル', 80003, 0, 2, 'あんたもコロ助も、浮かれて\\n転ぶんじゃないわよ？\\n…仕方ないから、あたしも\\n手を繋いであげるわよ', 0);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (293, 50, 0, '', 105801, 15, 'ペコリーヌ', 80003, 0, 0, 'あー！\u3000二人ともずるいです！\\nわたしもっ、ギュー♪', 0);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (294, 58, 0, '', 106001, 15, 'キャル', 80003, 0, 2, 'ちょっ、ペコリーヌ！\\nくっつき過ぎよ！', 0);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (295, 51, 0, '', 105801, 15, 'ペコリーヌ', 80003, 0, 0, '記念日だから\\n平気平気♪\\nやばいですね☆', 0);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (296, 59, 0, '', 106001, 15, 'キャル', 80003, 0, 2, '意味分かんないわよ！', 0);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (297, 42, 0, '', 105901, 15, 'コッコロ', 80003, 0, 1, 'ふふ。このめでたき日に\\n喜びがあふれておりますね\\n主さまは…いかがでしょうか？', 0);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (298, 43, 0, '', 105901, 15, 'コッコロ', 80003, 0, 1, '喜んでいただけているならば\\nわたくしはとてもとても\\n幸せでございます', 0);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (299, 52, 0, '', 105801, 15, 'ペコリーヌ', 80003, 0, 0, 'さぁ、2.5周年を\\n楽しみ尽くしますよ☆\\nまだまだ食べたいものもありますし\\nやりたいこともたくさんです！', 0);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (300, 60, 0, '', 106001, 15, 'キャル', 80003, 0, 2, '分かった、分かったから\\n引っ張るんじゃないわよ！\\n…そんな掴まなくても\\nちゃんとついていくから', 0);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (301, 44, 0, '', 105901, 15, 'コッコロ', 80003, 0, 1, 'ペコリーヌさま…キャルさま…\\n主さま…共にまいりましょう\\nどこまでも…！', 0);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (302, 53, 0, '', 105801, 15, 'ペコリーヌ', 80003, 0, 0, 'はい！\u3000それでは2.5周年\\n食べつくしツアーへ！\\nそして、その先の未来へ\\n向かって出発しましょう！', 0);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (303, 54, 0, '105901,45,106001,61', 105801, 15, 'ペコリーヌ・コッコロ・キャル', 80003, 0, 0, '2.5周年\\nありがとうございます！', 1);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (304, 1, 0, '', 190804, 0, 'カリン', 60002, 1, 1, '新年を迎え、新たに始まる一日を\\nおみくじで占ってみませんか？\\n良い運勢であるほど、\\n沢山のプレゼントが貰えますよ♪', 0);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (305, 0, 1, '', 0, 0, '', 60002, 1, 2, '今日の運勢は姫吉！\u3000どんな不可能も可能にできちゃう！\u3000\u3000\u3000\u3000仲間と食卓を囲めばさらに運気上昇よ！\u3000ただし魔物料理以外！', 0);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (306, 0, 1, '', 0, 0, '', 60002, 1, 2, '今日の運勢は姫吉！\u3000やること全てが最高潮！\u3000やばいですね☆\u3000ラッキーアイテムはおにぎり！\u3000お腹一杯で幸せが続くでしょう！', 0);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (307, 0, 1, '', 0, 0, '', 60002, 1, 2, '今日の運勢は姫吉！\u3000最強の運勢でどんなドジも跳ね除けます！\u3000大切な人と一緒に、最高の一日になること間違いなし！', 0);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (308, 0, 1, '', 0, 0, '', 60002, 1, 2, '今日の運勢は姫吉！\u3000どんな挑戦も上手くいく、最高の運勢です！理想の自分に変身できる絶好の機会！\u3000新しい一歩を踏み出そう！', 0);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (309, 0, 1, '', 0, 0, '', 60002, 2, 2, '今日の運勢は姫吉！\u3000やること全てが上手くいく最高の一日！\u3000\u3000あなたの活躍に先生もにっこりです。いい子いい子♪', 0);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (310, 0, 2, '', 0, 0, '', 60002, 1, 2, '今日の運勢は大吉！\u3000お裁縫好きな女の子のお墨付きです！\u3000\u3000\u3000お世話したがりの妹にめいっぱい愛されちゃうかも！？', 0);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (311, 0, 2, '', 0, 0, '', 60002, 1, 2, '今日の運勢は大吉！\u3000ラッキーカラーは赤！\u3000\u3000\u3000\u3000\u3000\u3000\u3000\u3000\u3000\u3000湧き上がるアイデアの数々に、高笑いが止まりませんわ！', 0);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (312, 0, 2, '', 0, 0, '', 60002, 1, 2, '今日の運勢は大吉！\u3000ラッキーワードは「ちぇる～ん♪」\u3000\u3000\u3000\u3000出会う人みんなに言ってあげると、ハッピーになれますよ！', 0);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (313, 0, 2, '', 0, 0, '', 60002, 1, 2, '今日の運勢は大吉！\u3000運勢はバッチリで無敵状態！\u3000\u3000\u3000\u3000\u3000\u3000\u3000龍眼で全てを見通して、思い通りの一日を過ごしましょう！', 0);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (314, 0, 2, '', 0, 0, '', 60002, 2, 2, '今日の運勢は大吉！\u3000悩んでいたことが解決しそうです！\u3000\u3000\u3000\u3000たまには勉強も仕事も忘れて、心あたたまる家族と過ごしましょ！', 0);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (315, 0, 3, '', 0, 0, '', 60002, 1, 2, '今日の運勢は中吉！\u3000家の中でゆっくり過ごすのがよさそう！\u3000\u3000ラッキーアイテムはゲームよ！\u3000ベストスコアを更新できるかも？', 0);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (316, 0, 3, '', 0, 0, '', 60002, 1, 2, '今日の運勢は中吉！\u3000上手くなりたいことに積極的に挑戦してみてサックス好きの妹が、手取り足取りサポートしてくれるかも～？', 0);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (317, 0, 3, '', 0, 0, '', 60002, 1, 2, '今日の運勢は中吉！\u3000仕事運が急上昇中です！\u3000\u3000\u3000\u3000\u3000\u3000\u3000\u3000\u3000きっと「煉獄に舞う一陣の疾風」の如き活躍ができますよ！', 0);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (318, 0, 3, '', 0, 0, '', 60002, 1, 2, '今日の運勢は中吉！\u3000日頃の努力が報われます！\u3000\u3000\u3000\u3000\u3000\u3000\u3000\u3000親しい友人がいるなら報告してみて。一緒に喜んでくれるはずだ。', 0);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (319, 0, 3, '', 0, 0, '', 60002, 1, 2, '今日の運勢は中吉！\u3000商売運が上がってきています！\u3000\u3000\u3000\u3000\u3000\u3000ラッキーアイテムはたい焼き！\u3000和菓子パワーで売上アップです！', 0);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (320, 0, 3, '', 0, 0, '', 60002, 1, 2, '今日の運勢は中吉！\u3000チャンスを待つと良い結果に！\u3000\u3000\u3000\u3000\u3000\u3000ラッキーアイテムのプリンを食べて、運を呼び込みましょう！', 0);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (321, 0, 3, '', 0, 0, '', 60002, 2, 2, '今日の運勢は中吉！\u3000運気が着々と上昇中！\u3000\u3000\u3000\u3000\u3000\u3000\u3000\u3000\u3000\u3000精霊の加護を受けたかのごとく、色々な事がうまくいきますよ♪', 0);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (322, 0, 4, '', 0, 0, '', 60002, 1, 2, '今日の運勢は小吉！\u3000まだ見ぬ危険が隠れているかも！\u3000\u3000\u3000\u3000\u3000でも安心しろ！\u3000提督が貴公を守ってくれるはずだぞ！', 0);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (323, 0, 4, '', 0, 0, '', 60002, 1, 2, '今日の運勢は小吉！\u3000いろんな事件が起こる一日になりそう！\u3000\u3000状況をよく観察してみようじゃないか！\u3000まさに探偵のごとくね！', 0);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (324, 0, 4, '', 0, 0, '', 60002, 1, 2, '今日の運勢は小吉！\u3000気の向くままに過ごすのが幸せへの近道！\u3000美味い魚を食べて猫を眺めて、自然体で過ごすのはどうだい？', 0);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (325, 0, 4, '', 0, 0, '', 60002, 1, 2, '今日の運勢は小吉！\u3000運気は高いけども、ハプニングには注意！\u3000出かけた先で、「ふしんしゃ」扱いされてしまうかも……', 0);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (326, 0, 4, '', 0, 0, '', 60002, 1, 2, '今日の運勢は小吉！\u3000同腹一心の友だちが見つかるかも！\u3000\u3000\u3000\u3000キーワードは「ユニちゃんズ」、記憶に刻みましょう！', 0);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (327, 0, 4, '', 0, 0, '', 60002, 1, 2, '今日の運勢は小吉！\u3000周りに流されず、マイペースな一日を！\u3000\u3000ただし寝すぎには注意ぐうたらし過ぎず適度な運動を、だってさ～', 0);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (328, 0, 4, '', 0, 0, '', 60002, 2, 2, '今日の運勢は小吉！\u3000根を詰めずにリラックスすると運気向上！\u3000ラッキーパーソンはアイドル。歌があなたを幸せにしてくれます♪', 0);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (329, 2, 0, '', 190804, 0, 'カリン', 60002, 0, 3, 'おみくじの結果はどうでしたか？\\n新たに始まる一日が、あなたに\\nとって良い日になりますように\\nまた明日も遊びに来て下さいね♪', 0);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (330, 3, 0, '', 190804, 7, 'カリン', 60002, 0, 3, 'おみくじは楽しんで頂けましたか？\\nあなたの新たなる年が\\n素晴らしいものになるよう、\\n心からお祈りいたします', 0);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (331, 1, 0, '', 105901, 1, 'コッコロ', 80005, 0, 4, 'ささ、シェフィさまはこちらへ…', 0);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (332, 1, 0, '', 106401, 1, 'シェフィ', 80005, 0, 0, 'コッコロさん、どこへ行くの…？\\n…え？', 0);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (333, 1, 0, '', 105801, 1, 'ペコリーヌ', 80005, 0, 3, '『おめでとうございます！\\nわ～パチパチー！』\\n…という感じでどうですかね！？', 0);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (334, 2, 0, '', 105901, 1, 'コッコロ', 80005, 0, 4, 'ではわたくしも\\n後ろからクラッカーを鳴らして\\n応戦いたします\\nああ、当日が待ち遠しいですね', 0);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (335, 2, 0, '', 106401, 1, 'シェフィ', 80005, 0, 0, 'ええと…\\n二人とも何をしているの？', 0);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (336, 1, 0, '', 106001, 1, 'キャル', 80005, 0, 1, 'シェフィは初めてだもんね\\nあの日が近いからって\\n予行練習してんのよ\\n気が早いわよね～', 0);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (337, 3, 0, '', 106401, 1, 'シェフィ', 80005, 0, 0, 'あの日…？', 0);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (338, 2, 0, '', 105801, 1, 'ペコリーヌ', 80005, 0, 3, 'その通りです…\\nいよいよ記念すべきあの日が\\n近づいてきましたよ！', 0);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (339, 3, 0, '', 105801, 1, 'ペコリーヌ', 80005, 0, 3, '『プリンセスコネクト！\\nRe:Dive』3.5周年！', 0);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (340, 1, 0, '', 190801, 1, 'カリン', 80005, 0, 2, 'やばいですね☆', 0);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (341, 2, 0, '', 106001, 1, 'キャル', 80005, 0, 1, 'って、なにしれっと\\n参加してんのよカリン！', 0);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (342, 2, 0, '', 190801, 1, 'カリン', 80005, 0, 2, 'ふふ、いいじゃないですか\\n【ギルド管理協会】として\\n私もみなさんと一緒に\\nお祝いをさせてください！', 0);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (343, 3, 0, '', 190801, 1, 'カリン', 80005, 0, 2, 'それに…記念日が近づけば\\nとっておきの情報を\\nお届けしますから♪', 0);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (344, 4, 0, '', 105801, 1, 'ペコリーヌ', 80005, 0, 3, 'というわけで\\n今日からシェフィちゃんも一緒に\\nカウントダウンしちゃいましょう！\\n3.5周年まで…', 0);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (345, 4, 0, '', 106401, 1, 'シェフィ', 80005, 0, 0, 'えっ！？\u3000ええとええと…！\\nあ、あと14日…！', 0);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (346, 5, 0, '', 105801, 2, 'ペコリーヌ', 80005, 0, 3, '3.5周年まであと13日\\n豪華に、そして盛大に\\nお祝いしたいですね☆', 0);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (347, 3, 0, '', 105901, 2, 'コッコロ', 80005, 0, 1, '豪華といえば前にとある貴族さまが\\n舞踏会を開かれたそうで\\n主さまがそのお手伝いを\\nしておりました', 0);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (348, 4, 0, '', 105901, 2, 'コッコロ', 80005, 0, 1, 'そこで美しい所作を学ばれたので\\nわたくしも教えていただきました\\nしゃなり、しゃなり…\\nいかがでしょう？', 0);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (349, 6, 0, '', 105801, 2, 'ペコリーヌ', 80005, 0, 3, 'すっごく上手ですよ☆\\nまるでお姫様みたいです\\nせっかくなのでわたしも\\nしゃなりしゃなり', 0);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (350, 5, 0, '', 105901, 2, 'コッコロ', 80005, 0, 1, 'さすがでございます\\nペコリーヌさま', 0);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (351, 3, 0, '', 106001, 2, 'キャル', 80005, 0, 0, 'いや、あんたは\\nできなきゃダメでしょ\\n本物のお姫様なんだし', 0);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (352, 5, 0, '', 106401, 2, 'シェフィ', 80005, 0, 2, 'しゃなり、しゃなり…\\nふふ、案外できるものね', 0);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (353, 7, 0, '', 105801, 2, 'ペコリーヌ', 80005, 0, 3, 'わぁ！\\nシェフィちゃん\\n姿勢がとってもキレイです♪', 0);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (354, 6, 0, '', 105901, 2, 'コッコロ', 80005, 0, 1, 'さ、次はキャルさまの\\n番でございますよ', 0);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (355, 4, 0, '', 106001, 2, 'キャル', 80005, 0, 0, 'あ、あたしはいいわよ！\\nそういうの全然分かんないし…', 0);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (356, 6, 0, '', 106401, 2, 'シェフィ', 80005, 0, 2, '大丈夫\\nやってみると結構楽しいわよ\\nほらほらっ', 0);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (357, 5, 0, '', 106001, 2, 'キャル', 80005, 0, 0, 'そ、そこまで言うなら…\\nしゃなにゅわきゃあっ！', 0);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (358, 6, 0, '', 106001, 2, 'キャル', 80005, 0, 0, 'いたたた…もぉお～！\\nなんであたしがこんな目に～！', 0);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (359, 7, 0, '', 105901, 2, 'コッコロ', 80005, 0, 1, 'まぁまぁ\\n記念日までに練習すれば\\nできるようになるかもしれません\\nよろしければお教えいたしますよ', 0);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (360, 7, 0, '', 106001, 2, 'キャル', 80005, 0, 0, 'よし！\\nあんたたちができて\\nあたしだけできないのはしゃくだし\\nやってやろうじゃないの！！', 0);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (361, 8, 0, '', 105901, 3, 'コッコロ', 80005, 0, 1, '3.5周年まであと12日\\n記念日当日はもちろんですが\\nその日を待つ時間というのも\\n心躍ります', 0);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (362, 8, 0, '', 105801, 3, 'ペコリーヌ', 80005, 0, 3, '分かりますっ！\\nどんな特別な料理を食べられるのか\\n考えるだけでワクワクしますよね！', 0);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (363, 9, 0, '', 105901, 3, 'コッコロ', 80005, 0, 1, '特別な料理といえば、お祭りですね\\nそういえば主さまは学生として\\n聖学祭に参加されたこと\\nがあるとか…', 0);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (364, 7, 0, '', 106401, 3, 'シェフィ', 80005, 0, 2, '聖学祭…って、なにかしら？', 0);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (365, 10, 0, '', 105901, 3, 'コッコロ', 80005, 0, 1, '聖テレサ女学院の祭典ですよ\\n二つのチームが競い合い\\n青春を満喫するのが趣旨のようです', 0);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (366, 8, 0, '', 106001, 3, 'キャル', 80005, 0, 0, 'それってカルミナの\\nサプライズライブがあった\\nお祭りよね？\\nちょっと見たかったかも…', 0);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (367, 9, 0, '', 106001, 3, 'キャル', 80005, 0, 0, 'カルミナの後の\\nライブも好評だったらしいじゃない\\n確か、なかよし部\\nだったっけ…？', 0);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (368, 9, 0, '', 105801, 3, 'ペコリーヌ', 80005, 0, 3, 'なかよし部…\\n仲が良さそうな名前で\\nやばいですね☆', 0);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (369, 10, 0, '', 106001, 3, 'キャル', 80005, 0, 0, 'いや、そのまんますぎでしょ…', 0);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (370, 8, 0, '', 106401, 3, 'シェフィ', 80005, 0, 2, '聖学祭かぁ…なんだか楽しそうね\\nそれになかよし部の人たちも\\n気になるわ', 0);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (371, 10, 0, '', 105801, 3, 'ペコリーヌ', 80005, 0, 3, 'それじゃあわたしたちも、\\n負けじと仲良くしましょう♪\\nほらほらシェフィちゃん、\\nぎゅーっ☆\u3000ですよ♪', 0);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (372, 9, 0, '', 106401, 3, 'シェフィ', 80005, 0, 2, 'えっ？\u3000ええ…\\nぎゅーっ…？', 0);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (373, 11, 0, '', 106001, 4, 'キャル', 80005, 0, 0, '3.5周年まであと11日！？\\nお祝いの準備進んでないんだけど…\\nああ～昨日に戻りたいわ…', 0);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (374, 10, 0, '', 106401, 4, 'シェフィ', 80005, 0, 2, 'そういえばそんな魔道具があるって\\n聞いたことがあるわね\\n確か、名前はタイムラーベ…', 0);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (375, 12, 0, '', 106001, 4, 'キャル', 80005, 0, 0, 'なにそれヤバいわね\\nでも本当にあるんだったら\\n準備よりももっとやり直したいこと\\nたくさんあるんだけど…', 0);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (376, 11, 0, '', 105901, 4, 'コッコロ', 80005, 0, 1, 'もしや正月の件でしょうか…？\\nあの時はお金がなくて\\n苦労しましたから', 0);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (377, 13, 0, '', 106001, 4, 'キャル', 80005, 0, 0, 'あれはそうね…\\nお金を湯水のように使う\\nぺコリーヌを止められたら\\nあんな苦労をすることもなかったし', 0);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (378, 11, 0, '', 105801, 4, 'ペコリーヌ', 80005, 0, 3, 'そんなこともありましたね！\\nやり直したいといえば\\n『きゃるきゃる～ん♪』\\nの方かと思いましたよ！', 0);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (379, 14, 0, '', 106001, 4, 'キャル', 80005, 0, 0, 'バラすんじゃないわよ\\nこのアホリーヌ！\\nシェフィはそれ\\n知らないんだから！', 0);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (380, 15, 0, '', 106001, 4, 'キャル', 80005, 0, 0, 'こうなったらもう、なんとか\\nタイムラーべを探し出して\\n今の会話をなかったことに…\\nって、どうしたのよシェフィ', 0);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (381, 11, 0, '', 106401, 4, 'シェフィ', 80005, 0, 2, 'うん…もし、私だったら…\\n私が知らないみんなとの時間を\\n見てみたいな、って…', 0);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (382, 12, 0, '', 105801, 4, 'ペコリーヌ', 80005, 0, 3, 'シェフィちゃん！\u3000タイムなんとか\\nなんかなくても大丈夫ですよ！\\n一緒の時間はこれから\\nどんどん作ればいいんですから！', 0);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (383, 12, 0, '', 105901, 4, 'コッコロ', 80005, 0, 1, 'はい、今この瞬間も\\n未来にはかけがえのない思い出に\\nなっていることでしょう', 0);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (384, 16, 0, '', 106001, 4, 'キャル', 80005, 0, 0, 'だからそんな顔しないの\\nほら、お祝いの準備、進めるわよ！', 0);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (385, 12, 0, '', 106401, 4, 'シェフィ', 80005, 0, 2, 'みんな…そうね\\n最高のお祝いにして\\n最高の思い出にしましょう！', 0);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (386, 13, 0, '', 105801, 5, 'ペコリーヌ', 80005, 0, 3, '3.5周年まで、あと10日！\\nもうすぐですよー！\\n楽しみすぎて、やばいですね！', 0);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (387, 14, 0, '', 105801, 5, 'ペコリーヌ', 80005, 0, 3, 'そういえば…たくさんのおもちゃが\\n子どもたちを襲うっていう\\n騒動もありましたね…\\nなんでも勝手に動き出したとか！', 0);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (388, 15, 0, '', 105801, 5, 'ペコリーヌ', 80005, 0, 3, '学校や孤児院とかに\\nちっちゃなおもちゃが乗り込んで\\n暴れたみたいですよ！', 0);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (389, 17, 0, '', 106001, 5, 'キャル', 80005, 0, 0, '暴れたって言っても\\n所詮はおもちゃじゃない\\nどうせちっさいんでしょ？', 0);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (390, 18, 0, '', 106001, 5, 'キャル', 80005, 0, 0, 'だったら魔法で\\n全部ぶっ飛ばせばいいじゃない！\\n大したことないわよ！', 0);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (391, 13, 0, '', 106401, 5, 'シェフィ', 80005, 0, 2, 'キャルってば…\\n相手は子どもが\\n大事にしてる物なのよ…？', 0);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (392, 13, 0, '', 105901, 5, 'コッコロ', 80005, 0, 1, '乱暴な発言は\\nめっ、でございますよ？\\n子どもの教育に悪影響を\\n与えてしまいますから…', 0);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (393, 16, 0, '', 105801, 5, 'ペコリーヌ', 80005, 0, 3, 'キャルちゃんだって\\n意外と猫グッズとか\\nたっくさん集めてますよね？\\nもしその子たちが暴れたら…？', 0);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (394, 19, 0, '', 106001, 5, 'キャル', 80005, 0, 0, 'う、うっさいわね！\\n意外とか言うな！\\n…ま、まあ確かに正面切って\\n魔法でぶっ飛ばせないかもね…', 0);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (395, 17, 0, '', 105801, 5, 'ペコリーヌ', 80005, 0, 3, 'あはは☆\\nキャルちゃんのそういうところ\\n好きですよ♪', 0);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (396, 18, 0, '', 105801, 5, 'ペコリーヌ', 80005, 0, 3, 'そんなキャルちゃんに猫グッズを\\nプレゼントしちゃいますね！\\n一部で流行っていた、たい焼き屋の\\nおまけフィギュアですよ♪', 0);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (397, 19, 0, '', 105801, 5, 'ペコリーヌ', 80005, 0, 3, '乱暴に扱ったりしないでくださいね\\nひとりでに暴れ出しちゃうかも\\nしれませんから！', 0);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (398, 4, 0, '', 190801, 6, 'カリン', 80005, 0, 2, '3.5周年まであと９日\\nここでみなさんに\\nビックニュースですよ！', 0);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (399, 5, 0, '', 190801, 6, 'カリン', 80005, 0, 2, '3.5周年を祝う生放送に\\n去年と同様【美食殿】の\\nみなさんにご出演いただくことが\\n決定しましたー！', 0);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (400, 20, 0, '', 106001, 6, 'キャル', 80005, 0, 1, '…えっ！？', 0);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (401, 20, 0, '', 105801, 6, 'ペコリーヌ', 80005, 0, 3, '本当ですか！？\\nそれじゃ今から張り切って\\n生放送中に食べる魔物料理を\\n作らなくちゃですね☆', 0);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (402, 14, 0, '', 106401, 6, 'シェフィ', 80005, 0, 0, 'いや…がんばるところは\\nそこじゃないような…\\nというか去年も出演してたのね\\nすごいじゃない！', 0);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (403, 14, 0, '', 105901, 6, 'コッコロ', 80005, 0, 4, 'はい。とても緊張しますが\\nやりがいのある大役です\\n一緒にがんばりましょうね\\nシェフィさま', 0);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (404, 15, 0, '', 106401, 6, 'シェフィ', 80005, 0, 0, 'わ、私も出るの！？\u3000でも…\\n私も【美食殿】の一人だものね\\nそれなら今からしっかり準備をして\\nコンディションを整えないと…', 0);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (405, 21, 0, '', 106001, 6, 'キャル', 80005, 0, 1, 'ふふん♪\\n生放送直前のカチコチになった\\nシェフィの姿が楽しみだわ！', 0);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (406, 21, 0, '', 105801, 6, 'ペコリーヌ', 80005, 0, 3, '去年のキャルちゃんは\\n緊張しすぎてずっと震えて\\nかわいかったですもんね！\\n今年もあの姿が見たいです！', 0);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (407, 22, 0, '', 106001, 6, 'キャル', 80005, 0, 1, 'ぶっ殺すぞ！？', 0);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (408, 6, 0, '', 190801, 6, 'カリン', 80005, 0, 2, 'というわけで\\n『プリンセスコネクト！\\nRe:Dive』の魅力を\\nお伝えする生放送をお楽しみに♪', 0);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (409, 15, 0, '', 105901, 7, 'コッコロ', 80005, 0, 1, '3.5周年まであと８日\\nでございますよ\\n楽しみですね、主さま', 0);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (410, 23, 0, '', 106001, 7, 'キャル', 80005, 0, 0, 'そういえばあんた\\n夏休みの宿題は\\nきちんとやってるの？', 0);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (411, 16, 0, '', 106401, 7, 'シェフィ', 80005, 0, 2, '宿題…学校に通うのも\\n楽しいことばかりじゃ\\nないのね', 0);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (412, 22, 0, '', 105801, 7, 'ペコリーヌ', 80005, 0, 3, 'あれ？\u3000そういえば\\n少し前にルーセント学院で\\n何かあったような…', 0);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (413, 24, 0, '', 106001, 7, 'キャル', 80005, 0, 0, 'ああ、始業式の日に\\n大捕り物があったって\\n話題になってたわね', 0);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (414, 17, 0, '', 106401, 7, 'シェフィ', 80005, 0, 2, '夏休みを終わらせないって\\n騒いでたっていう話？\\nあれ本当なの？\\n都市伝説だと思ってたわ', 0);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (415, 16, 0, '', 105901, 7, 'コッコロ', 80005, 0, 1, 'その一件ならよく存じ上げて\\nおります。ですから主さま\\n次の機会にはわたくしと一緒に\\nがんばりましょう', 0);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (416, 18, 0, '', 106401, 7, 'シェフィ', 80005, 0, 2, '楽しそう…私も一緒にやりたいな\\nママ…じゃ、じゃなくて！\\nコッコロさん、私もまざっていい？', 0);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (417, 17, 0, '', 105901, 7, 'コッコロ', 80005, 0, 1, 'もちろんでございます\\n仲良くお勉強いたしましょう', 0);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (418, 25, 0, '', 106001, 7, 'キャル', 80005, 0, 0, 'しれっと教育ママが\\n生まれてる…？', 0);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (419, 23, 0, '', 105801, 7, 'ペコリーヌ', 80005, 0, 3, 'お勉強は大切ですよ！\\nキャルちゃんも一緒に\\nがんばりましょう！', 0);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (420, 26, 0, '', 106001, 7, 'キャル', 80005, 0, 0, 'え～～～～！？', 0);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (421, 27, 0, '', 106001, 8, 'キャル', 80005, 0, 0, '3.5周年まであと７日〜♪\\nふふ～ん♪\\nふんふふ～ん♪', 0);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (422, 19, 0, '', 106401, 8, 'シェフィ', 80005, 0, 2, '…\\nねぇコッコロさん\\nキャル、どうしちゃったの？', 0);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (423, 18, 0, '', 105901, 8, 'コッコロ', 80005, 0, 1, 'とてもご機嫌そうに\\n鼻歌を歌ってらっしゃいますね\\n耳も尻尾もリズミカルに\\n揺れて…ノリノリでございます', 0);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (424, 24, 0, '', 105801, 8, 'ペコリーヌ', 80005, 0, 3, 'あれはですね！\\nカルミナのみなさんの\\nサマーライブのチケットが\\n手に入ったからなんですよ♪', 0);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (425, 20, 0, '', 106401, 8, 'シェフィ', 80005, 0, 2, 'ええっ！？\\nあのライブのチケットって確か\\n入手困難だったんじゃ…', 0);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (426, 28, 0, '', 106001, 8, 'キャル', 80005, 0, 0, 'ふふふふ～ん♪\\nしゃいにんぐふゅ～ちゃ～♪', 0);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (427, 19, 0, '', 105901, 8, 'コッコロ', 80005, 0, 1, 'なるほど…\\nキャルさまがあのように\\nなってしまうのも頷けますね', 0);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (428, 21, 0, '', 106401, 8, 'シェフィ', 80005, 0, 2, '…カルミナの\\n『Shining Future』\\nの中に、シャイニングフューチャー\\nって歌詞はなかったはずだけど…', 0);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (429, 29, 0, '', 106001, 8, 'キャル', 80005, 0, 0, 'ふんふ…はっ！？\\nあっ、あんたたち！\\nなに人の鼻歌を\\n勝手に聞いてるのよ！？', 0);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (430, 30, 0, '', 106001, 8, 'キャル', 80005, 0, 0, 'こっ、これは別に\\nカルミナの曲じゃなくて…\\nあたしのオリジナルソングよ！\\n聞いたらお金取るわよっ！？', 0);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (431, 25, 0, '', 105801, 8, 'ペコリーヌ', 80005, 0, 3, 'えへへ、キャルちゃん\\nカルミナのサマーライブ\\n思いっきり楽しみましょうね☆', 0);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (432, 31, 0, '', 106001, 8, 'キャル', 80005, 0, 0, 'も～っ！\\n生暖かい目で見るな～～！\\nぶっ殺すわよ～～～！', 0);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (433, 22, 0, '', 106401, 9, 'シェフィ', 80005, 0, 0, '3.5周年まであと６日\\n３人も言ってたけど\\nあっという間だったわね', 0);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (434, 23, 0, '', 106401, 9, 'シェフィ', 80005, 0, 0, '…えっ？\\n生放送の意気込み！？\\n突然なに！？', 0);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (435, 24, 0, '', 106401, 9, 'シェフィ', 80005, 0, 0, 'ええと…\\nとにかく失敗しないように\\n台本たくさん読んで…\\nそれから…', 0);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (436, 25, 0, '', 106401, 9, 'シェフィ', 80005, 0, 0, 'えっ！？\\nトラブルがあったら\\nどうするのかって！？\\nそ、それは…！', 0);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (437, 26, 0, '', 106401, 9, 'シェフィ', 80005, 0, 0, 'とにかく落ち着いて\\nスタッフさんの指示を聞いて…', 0);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (438, 27, 0, '', 106401, 9, 'シェフィ', 80005, 0, 0, 'それから、それから…！\\nぅ、ぅぅっ…！', 0);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (439, 28, 0, '', 106401, 9, 'シェフィ', 80005, 0, 0, '―びえぇぇ～んっ！！！', 0);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (440, 20, 0, '', 105901, 9, 'コッコロ', 80005, 0, 1, 'どうされましたか、シェフィさま', 0);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (441, 29, 0, '', 106401, 9, 'シェフィ', 80005, 0, 0, 'ううっ…ひっく…\\nママッ…！', 0);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (442, 21, 0, '', 105901, 9, 'コッコロ', 80005, 0, 1, 'よしよし、緊張されてるのですね\\nママが傍におりますよ\\n主さま、少々お待ちくださいませ', 0);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (443, 22, 0, '', 105901, 9, 'コッコロ', 80005, 0, 1, '…ふぅ\\nシェフィさま\\n生放送への意気込み\\nお話しできそうですか？', 0);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (444, 30, 0, '', 106401, 9, 'シェフィ', 80005, 0, 0, '…ううっ\\n恥ずかしすぎて\\nもう生放送出られない…', 0);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (445, 23, 0, '', 105901, 10, 'コッコロ', 80005, 0, 0, '主さま\\n3.5周年まであと５日\\nでございます', 0);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (446, 24, 0, '', 105901, 10, 'コッコロ', 80005, 0, 0, 'ですがその前に\\n生放送がありますね', 0);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (447, 25, 0, '', 105901, 10, 'コッコロ', 80005, 0, 0, '…生放送に向けた\\n意気込みでございますか？', 0);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (448, 26, 0, '', 105901, 10, 'コッコロ', 80005, 0, 0, 'もちろんわたくしは\\n主さまのために\\n全身全霊を込めて\\n楽しい時間をご提供いたします', 0);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (449, 27, 0, '', 105901, 10, 'コッコロ', 80005, 0, 0, '…と、意気込んでみましたが\\nうまくできるか少し不安です\\n声が小さくなったり\\n間違えてしまったらどうしようと…', 0);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (450, 28, 0, '', 105901, 10, 'コッコロ', 80005, 0, 0, 'ですがわたくしは\\n一人ではありません\\n【美食殿】のみなさまが\\nおります', 0);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (451, 29, 0, '', 105901, 10, 'コッコロ', 80005, 0, 0, 'どんな困難も\\nみなさまと一緒なら\\n乗り越えられると\\nわたくし、確信しております', 0);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (452, 30, 0, '', 105901, 10, 'コッコロ', 80005, 0, 0, 'それに今回はシェフィさまも\\nご参加されるわけですし\\nママとしてお手本に\\nならねばなりませんね', 0);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (453, 31, 0, '', 105901, 10, 'コッコロ', 80005, 0, 0, '主さま。3.5周年も\\n食卓を囲んでいる時のような\\n楽しい思い出を\\n一緒に作りましょうね', 0);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (454, 26, 0, '', 105801, 11, 'ペコリーヌ', 80005, 0, 0, '3.5周年まであと４日！\\nやばいですね☆', 0);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (455, 32, 0, '', 106001, 11, 'キャル', 80005, 0, 1, 'はいはい、やばいわね\\nというかもうすぐ生放送だけど\\nあんた準備はできてるの？', 0);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (456, 27, 0, '', 105801, 11, 'ペコリーヌ', 80005, 0, 0, 'ばっちりオイッスー☆\u3000ですよ！\\n『王家の装備』も全開です！', 0);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (457, 28, 0, '', 105801, 11, 'ペコリーヌ', 80005, 0, 0, 'あとは前回を超える\\n最高のオイッスー☆\u3000を\\nお届けできるように\\n練習あるのみですかね！', 0);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (458, 29, 0, '', 105801, 11, 'ペコリーヌ', 80005, 0, 0, 'キャルちゃんは\\nどうなんですか？\\nオイッスー☆\u3000を\\n毎日ちゃんと練習してますか？', 0);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (459, 33, 0, '', 106001, 11, 'キャル', 80005, 0, 1, 'はぁ！？\u3000なんであたしまで\\nその変なあいさつを練習しないと\\nいけないのよ！', 0);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (460, 30, 0, '', 105801, 11, 'ペコリーヌ', 80005, 0, 0, 'もしかしてやってないんですか？\\nダメですよキャルちゃん！\\nシェフィちゃんだってちゃんと\\n毎日練習してるのに！', 0);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (461, 31, 0, '', 105801, 11, 'ペコリーヌ', 80005, 0, 0, 'こうなったらわたしがキャルちゃん\\nにオイッスー☆\u3000の『オ』から\\nしっかり教えてあげないと！', 0);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (462, 32, 0, '', 105801, 11, 'ペコリーヌ', 80005, 0, 0, 'オイッスー☆\u3000の『オ』は\\n口を大きく開いて〜\\nドラゴンの骨つき肉に\\nかぶりつく直前をイメージして〜', 0);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (463, 34, 0, '', 106001, 11, 'キャル', 80005, 0, 1, 'だからあたしはやるなんて一言も…', 0);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (464, 33, 0, '', 105801, 11, 'ペコリーヌ', 80005, 0, 0, 'オイッスー☆', 0);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (465, 35, 0, '', 106001, 11, 'キャル', 80005, 0, 1, '聞きなさいっての！！', 0);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (466, 31, 0, '', 106401, 12, 'シェフィ', 80005, 0, 2, '3.5周年まであと３日…\\nそして生放送は、明日…', 0);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (467, 32, 0, '', 106401, 12, 'シェフィ', 80005, 0, 2, 'もっと台本を\\n読み込んでおかないと…\\nあと発声練習も…', 0);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (468, 33, 0, '', 106401, 12, 'シェフィ', 80005, 0, 2, 'おいっす！\\n…こうじゃなかったわね\\nええと確か…', 0);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (469, 34, 0, '', 106401, 12, 'シェフィ', 80005, 0, 2, 'うう…あんなに練習したのに\\nこれじゃみんなに迷惑かけちゃう…', 0);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (470, 35, 0, '', 106401, 12, 'シェフィ', 80005, 0, 2, '【美食殿】の一員として\\n認められるように\\n頑張らないといけないのに\\nよし、もう一度…', 0);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (471, 34, 0, '', 105801, 12, 'ペコリーヌ', 80005, 0, 3, 'やってますねシェフィちゃん！', 0);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (472, 36, 0, '', 106001, 12, 'キャル', 80005, 0, 0, 'なによ、考えることは\\nみんな同じってこと？', 0);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (473, 32, 0, '', 105901, 12, 'コッコロ', 80005, 0, 1, 'ふふ。シェフィさま\\nよろしければ\\n仲間に入れてください\\n一緒にやればきっとうまくできます', 0);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (474, 36, 0, '', 106401, 12, 'シェフィ', 80005, 0, 2, 'みんな…もちろんよ！', 0);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (475, 35, 0, '', 105801, 12, 'ペコリーヌ', 80005, 0, 3, 'それじゃ明日の生放送に向けて\\n一緒に練習がんばりましょう☆', 0);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (476, 7, 0, '', 190801, 13, 'カリン', 80005, 0, 2, '3.5周年まであと２日と\\n迫った本日は…\\nいよいよ生放送です！', 0);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (477, 8, 0, '', 190801, 13, 'カリン', 80005, 0, 2, '【美食殿】のみなさんが\\n準備に入られていますので\\nそれぞれ繋いでみましょう！\\nまずはペコリーヌさんです！', 0);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (478, 36, 0, '', 105801, 13, 'ペコリーヌ', 80005, 0, 3, '今日もオイッスー☆\\nみんなで一緒に\\nオイッスー☆', 0);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (479, 9, 0, '', 190801, 13, 'カリン', 80005, 0, 2, 'お手本になるような\\n発声練習ですね！\\nそれでは続いてコッコロさん', 0);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (480, 33, 0, '', 105901, 13, 'コッコロ', 80005, 0, 4, 'はじめちょろちょろ\\nなかぱっぱ～♪\\n生放送前にみなさまで\\n食卓を囲んで英気を養いましょう', 0);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (481, 10, 0, '', 190801, 13, 'カリン', 80005, 0, 2, 'さすが【美食殿】のママですね！\\nそしてキャルさんは…', 0);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (482, 37, 0, '', 106001, 13, 'キャル', 80005, 0, 1, '大丈夫…大丈夫…\\nあたしは大丈夫…', 0);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (483, 11, 0, '', 190801, 13, 'カリン', 80005, 0, 2, 'す、すごく震えてますけど\\n大丈夫でしょうか…？\\nそして今回初参加となる\\n期待の新人シェフィさん！', 0);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (484, 37, 0, '', 106401, 13, 'シェフィ', 80005, 0, 0, 'あうー？', 0);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (485, 37, 0, '105901,34,106001,38,190801,12', 105801, 13, 'みんな', 80005, 0, 4, 'あ…', 1);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (486, 39, 0, '', 106001, 13, 'キャル', 80005, 0, 1, 'ちょ、ちょっとシェフィ！？\\nなに赤ちゃん返りしてん―\\nあ痛ぁっ！\\n噛んだわこいつーっ！', 0);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (487, 35, 0, '', 105901, 13, 'コッコロ', 80005, 0, 4, 'シェフィさま\\n緊張しすぎて\\nしまったのでしょうね…\\nおーよしよし…', 0);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (488, 38, 0, '', 105801, 13, 'ペコリーヌ', 80005, 0, 3, 'シェフィちゃん！\\nそういう時は手のひらに\\n好きな文字を書いて\\n食べちゃうといいですよ！', 0);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (489, 13, 0, '', 190801, 13, 'カリン', 80005, 0, 2, '…ええと、現場からは以上です！\\n生放送はもうすぐ！\\n特別なお知らせもありますので\\nどうぞお楽しみに！', 0);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (490, 38, 0, '', 106401, 14, 'シェフィ', 80005, 0, 2, '3.5周年の記念日も\\nいよいよ明日ね\\n…って、あれ？', 0);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (491, 39, 0, '', 105801, 14, 'ペコリーヌ', 80005, 0, 3, '記念日はこの森へ行きませんか！？\\nすっごく美味しいお肉が\\nとれるんです☆', 0);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (492, 40, 0, '', 106001, 14, 'キャル', 80005, 0, 0, 'うげ、またあの魔物？\\nさすがに今度は\\n丸焼きとかはやめてよね…\\n見た目がヤバすぎるし', 0);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (493, 36, 0, '', 105901, 14, 'コッコロ', 80005, 0, 1, 'ふふ、キャルさまもだいぶ\\n魔物肉に慣れてきたようですね\\n調理ならばわたくしに\\nお任せください♪', 0);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (494, 39, 0, '', 106401, 14, 'シェフィ', 80005, 0, 2, 'みんな、何をしているの？\\nなんだか、\\n不穏な単語が聞こえたんだけど…', 0);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (495, 40, 0, '', 105801, 14, 'ペコリーヌ', 80005, 0, 3, 'シェフィちゃん！\\n明日の食べ尽くしツアーの\\n相談をしてたんですよ！', 0);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (496, 37, 0, '', 105901, 14, 'コッコロ', 80005, 0, 1, 'はい。明日は【美食殿】の\\n一員となったシェフィさまと一緒に\\n初めて記念日を過ごすのですから\\n特別なコース料理を用意しませんと', 0);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (497, 41, 0, '', 106001, 14, 'キャル', 80005, 0, 0, 'ふふん♪\\n猫の毛も逆立つような\\nあれこれを食べさせられるから\\n覚悟しておいたほうがいいわよ？', 0);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (498, 40, 0, '', 106401, 14, 'シェフィ', 80005, 0, 2, 'へ、へぇ…', 0);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (499, 41, 0, '', 105801, 14, 'ペコリーヌ', 80005, 0, 3, '期待しててくださいね！\\nシェフィちゃんとあなたに\\n『おいちー！』って喜んでもらえる\\n最高のごちそうを準備しますから☆', 0);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (500, 41, 0, '', 106401, 14, 'シェフィ', 80005, 0, 2, 'ええと…その…うーんと…\\nわ、分かったわ\\n私も【美食殿】の一員だもの', 0);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (501, 42, 0, '', 106401, 14, 'シェフィ', 80005, 0, 2, 'それにあなたも一緒みたいだし\\n最後までがんばってみるわ…！', 0);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (502, 42, 0, '', 105801, 15, 'ペコリーヌ', 80005, 0, 3, 'それではいつものあれを\\nやりましょう！\\n準備はいいですかっ？\\n…いっきますよー！', 0);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (503, 42, 0, '', 106001, 15, 'キャル', 80005, 0, 1, '祝！', 0);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (504, 38, 0, '', 105901, 15, 'コッコロ', 80005, 0, 4, '3.5周年！', 0);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (505, 43, 0, '', 106401, 15, 'シェフィ', 80005, 0, 0, 'おめでとうございます！', 0);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (506, 14, 0, '', 190801, 15, 'カリン', 80005, 0, 2, 'この日を迎えられたのも\\nあなたが『プリンセスコネクト！\\nRe:Dive』を遊んでくれている\\nおかげです！', 0);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (507, 15, 0, '', 190801, 15, 'カリン', 80005, 0, 2, 'ということで\\nみなさんからあなたへ一言ずつ\\n感謝の言葉をどうぞ！', 0);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (508, 43, 0, '', 105801, 15, 'ペコリーヌ', 80005, 0, 3, '感謝の言葉ですか？\u3000わたしは\\n毎日あなたに感謝してますよ\\n【美食殿】の仲間になってくれて…\\n一緒にごはんを食べてくれて…', 0);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (509, 44, 0, '', 105801, 15, 'ペコリーヌ', 80005, 0, 3, 'なにより今でもわたしをぺコリーヌ\\nって呼んでくれてありがとうござい\\nます。これからもわたしはあなたの\\nぺコリーヌです！\u3000やばいですね☆', 0);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (510, 43, 0, '', 106001, 15, 'キャル', 80005, 0, 1, 'えっ！？\u3000今度はあたし！？\\n感謝って…まぁ、そうね…\\nあんたにはあたしが\\n辛くて苦しい時に助けてもらって…', 0);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (511, 44, 0, '', 106001, 15, 'キャル', 80005, 0, 1, 'でもおかげで色々吹っ切れたわ！\\nもしあんたが困ってたら今度は\\nあたしが助けてあげるから\\nその時はちゃんと言いなさいよ！', 0);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (512, 44, 0, '', 106401, 15, 'シェフィ', 80005, 0, 0, 'ええと…次は私ね\\n実はよく覚えてないのだけど\\n空から落ちてきた私を受け止めて\\nくれたのはあなたなのでしょう？', 0);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (513, 45, 0, '', 106401, 15, 'シェフィ', 80005, 0, 0, '最初に私を見つけてくれたのが\\nあなたで良かったって思ってるの\\nおかげで私は居場所を見つけたから\\nあなたがくれたもの、大切にするわ', 0);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (514, 39, 0, '', 105901, 15, 'コッコロ', 80005, 0, 4, 'では最後にわたくしから…\\nわたくしは主さまの元を離れた日…\\nこのように記念日をお祝いする\\nことは二度とないと思っていました', 0);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (515, 40, 0, '', 105901, 15, 'コッコロ', 80005, 0, 4, 'ですが、主さまはわたくしを\\n迎えにきてくださり、今もこうして\\nおそばにおいてくださっています\\nわたくしにとって毎日が記念日です', 0);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (516, 41, 0, '', 105901, 15, 'コッコロ', 80005, 0, 4, 'わたくしたちの物語は\\nまだ続いていきます\\nこれからも一緒にページを\\n作っていきましょうね', 0);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (517, 45, 0, '', 105801, 15, 'ペコリーヌ', 80005, 0, 3, 'それじゃ\\nいつものあれでしめますよ！\\nみんなで一緒に、さんはい☆', 0);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (518, 46, 0, '105901,42,106001,45,106401,46,190801,16', 105801, 15, 'みんな', 80005, 0, 4, 'これからも\\nよろしくおねがいします！', 1);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (519, 1, 0, '', 190804, 0, 'カリン', 60003, 1, 1, '新年を迎え、新たに始まる一日を\\nおみくじで占ってみませんか？\\n良い運勢であるほど、\\n沢山のプレゼントが貰えますよ♪', 0);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (520, 0, 1, '', 0, 0, '', 60003, 1, 2, '今日の運勢は姫吉！\u3000どんな不可能も可能にできちゃう！\u3000\u3000\u3000\u3000仲間と食卓を囲めばさらに運気上昇よ！\u3000ただし魔物料理以外！', 0);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (521, 0, 1, '', 0, 0, '', 60003, 1, 2, '今日の運勢は姫吉！\u3000やること全てが最高潮！\u3000やばいですね☆\u3000ラッキーアイテムはおにぎり！\u3000お腹一杯で幸せが続くでしょう！', 0);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (522, 0, 1, '', 0, 0, '', 60003, 1, 2, '今日の運勢は姫吉！\u3000羽が生えたように飛躍できる絶好調の運気！新しいことに挑戦するなら今しかないわ！\u3000やってみましょう！', 0);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (523, 0, 1, '', 0, 0, '', 60003, 1, 2, '今日の運勢は姫吉！\u3000精霊も新年の幸福をお祝いしています！\u3000\u3000主さまの笑顔が見られて、わたくしも幸せいっぱいでございます♪', 0);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (524, 0, 1, '', 0, 0, '', 60003, 2, 2, '今日の運勢は姫吉！\u3000やること全てが上手くいく最高の一日！\u3000\u3000あなたの活躍に先生もにっこりです。いい子いい子♪', 0);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (525, 0, 2, '', 0, 0, '', 60003, 1, 2, '今日の運勢は大吉！\u3000お裁縫好きな女の子のお墨付きです！\u3000\u3000\u3000お世話したがりの妹にめいっぱい愛されちゃうかも！？', 0);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (526, 0, 2, '', 0, 0, '', 60003, 1, 2, '今日の運勢は大吉！\u3000ラッキーカラーは赤！\u3000\u3000\u3000\u3000\u3000\u3000\u3000\u3000\u3000\u3000湧き上がるアイデアの数々に、高笑いが止まりませんわ！', 0);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (527, 0, 2, '', 0, 0, '', 60003, 1, 2, '今日の運勢は大吉！\u3000ラッキーカラーは鮮やかな黄色！\u3000\u3000\u3000\u3000\u3000さらにシマシマのアイテムを持つと、運気倍増らしいッスよ♪', 0);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (528, 0, 2, '', 0, 0, '', 60003, 1, 2, '今日の運勢は大吉！\u3000秘められた力が開花するでしょう！\u3000\u3000\u3000\u3000じゃあ、私の龍眼と力比べしてみようか？\u3000ふふ、冗談だよ～', 0);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (529, 0, 2, '', 0, 0, '', 60003, 2, 2, '今日の運勢は大吉！\u3000悩んでいたことが解決しそうです！\u3000\u3000\u3000\u3000たまには勉強も仕事も忘れて、心あたたまる家族と過ごしましょ！', 0);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (530, 0, 3, '', 0, 0, '', 60003, 1, 2, '今日の運勢は中吉！\u3000家の中でゆっくり過ごすのがよさそう！\u3000\u3000ラッキーアイテムはゲームよ！\u3000ベストスコアを更新できるかも？', 0);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (531, 0, 3, '', 0, 0, '', 60003, 1, 2, '今日の運勢は中吉！\u3000上手くなりたいことに積極的に挑戦してみてサックス好きの妹が、手取り足取りサポートしてくれるかも～？', 0);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (532, 0, 3, '', 0, 0, '', 60003, 1, 2, '今日の運勢は中吉！\u3000仕事運が急上昇中です！\u3000\u3000\u3000\u3000\u3000\u3000\u3000\u3000\u3000きっと「煉獄に舞う一陣の疾風」の如き活躍ができますよ！', 0);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (533, 0, 3, '', 0, 0, '', 60003, 1, 2, '今日の運勢は中吉！\u3000日頃の努力が報われます！\u3000\u3000\u3000\u3000\u3000\u3000\u3000\u3000親しい友人がいるなら報告してみて。一緒に喜んでくれるはずだ。', 0);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (534, 0, 3, '', 0, 0, '', 60003, 1, 2, '今日の運勢は中吉！\u3000ラッキーアイテムはかわいいもの！\u3000\u3000\u3000\u3000ア、アタシはかわいいじゃなくてキレイだってば！\u3000も～っ！', 0);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (535, 0, 3, '', 0, 0, '', 60003, 1, 2, '今日の運勢は中吉！\u3000チャンスを待つと良い結果に！\u3000\u3000\u3000\u3000\u3000\u3000ラッキーアイテムのプリンを食べて、運を呼び込みましょう！', 0);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (536, 0, 3, '', 0, 0, '', 60003, 2, 2, '今日の運勢は中吉！\u3000悩まず行動すれば強運に恵まれる！\u3000\u3000\u3000\u3000守るよりも攻めるが吉だ！\u3000勝負事をするにはいい運勢だな！', 0);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (537, 0, 4, '', 0, 0, '', 60003, 1, 2, '今日の運勢は小吉！\u3000まだ見ぬ危険が隠れているかも！\u3000\u3000\u3000\u3000\u3000でも安心しろ！\u3000提督が貴公を守ってくれるはずだぞ！', 0);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (538, 0, 4, '', 0, 0, '', 60003, 1, 2, '今日の運勢は小吉！\u3000いろんな事件が起こる一日になりそう！\u3000\u3000状況をよく観察してみようじゃないか！\u3000まさに探偵のごとくね！', 0);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (539, 0, 4, '', 0, 0, '', 60003, 1, 2, '今日の運勢は小吉！\u3000気の向くままに過ごすのが幸せへの近道！\u3000美味い魚を食べて猫を眺めて、自然体で過ごすのはどうだい？', 0);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (540, 0, 4, '', 0, 0, '', 60003, 1, 2, '今日の運勢は小吉！\u3000難しい頼み事をされるかもしれません！\u3000\u3000うまくやれればきっと成長につながります、挑戦してみましょう！', 0);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (541, 0, 4, '', 0, 0, '', 60003, 1, 2, '今日の運勢は小吉！\u3000同腹一心の友だちが見つかるかも！\u3000\u3000\u3000\u3000キーワードは「ユニちゃんズ」、記憶に刻みましょう！', 0);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (542, 0, 4, '', 0, 0, '', 60003, 1, 2, '今日の運勢は小吉！\u3000周りに流されず、マイペースな一日を！\u3000\u3000ただし寝すぎには注意ぐうたらし過ぎず適度な運動を、だってさ～', 0);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (543, 0, 4, '', 0, 0, '', 60003, 2, 2, '今日の運勢は小吉！\u3000無理は禁物、お家で静かにしていましょう\u3000プロぼっちの私が、お家での過ごし方……教えてあげましょうか？', 0);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (544, 2, 0, '', 190804, 0, 'カリン', 60003, 0, 3, 'おみくじの結果はどうでしたか？\\n新たに始まる一日が、あなたに\\nとって良い日になりますように\\nまた明日も遊びに来て下さいね♪', 0);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (545, 3, 0, '', 190804, 7, 'カリン', 60003, 0, 3, 'おみくじは楽しんで頂けましたか？\\nあなたの新たなる年が\\n素晴らしいものになるよう、\\n心からお祈りいたします', 0);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (546, 1, 0, '', 190804, 0, 'カリン', 60004, 1, 1, '新年を迎え、新たに始まる一日を\\nおみくじで占ってみませんか？\\n良い運勢であるほど、\\n沢山のプレゼントが貰えますよ♪', 0);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (547, 0, 1, '', 0, 0, '', 60004, 1, 2, '今日の運勢は姫吉！\u3000やること全てが最高潮！\u3000やばいですね☆\u3000ラッキーアイテムはおにぎり！\u3000お腹一杯で幸せが続くでしょう！', 0);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (548, 0, 1, '', 0, 0, '', 60004, 1, 2, '今日の運勢は姫吉！\u3000羽が生えたように飛躍できる絶好調の運気！新しいことに挑戦するなら今しかないわ！\u3000やってみましょう！', 0);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (549, 0, 1, '', 0, 0, '', 60004, 1, 2, '今日の運勢は姫吉！\u3000宴でも開きたくなるほどの絶対幸運！\\nイメチェンでもしてみるのはどうだ？\u3000ぴょんぴょん、なんてな♪', 0);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (550, 0, 1, '', 0, 0, '', 60004, 1, 2, '今日の運勢は姫吉！\u3000ずっと祈り続けていた願いが叶うかも！\\nきっとあんたならたどり着けるわ、ハッピーエンドのその先に', 0);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (551, 0, 1, '', 0, 0, '', 60004, 1, 2, '今日の運勢は姫吉！\u3000やること全てが上手くいく最高の一日！\u3000\u3000あなたの活躍に先生もにっこりです。いい子いい子♪', 0);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (552, 0, 2, '', 0, 0, '', 60004, 1, 2, '今日の運勢は大吉！\u3000悩んでいたことが解決しそうです！\u3000\u3000\u3000\u3000たまには勉強も仕事も忘れて、心あたたまる家族と過ごしましょ！', 0);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (553, 0, 2, '', 0, 0, '', 60004, 2, 2, '今日の運勢は大吉！\u3000ラッキーカラーは赤！\u3000\u3000\u3000\u3000\u3000\u3000\u3000\u3000\u3000\u3000湧き上がるアイデアの数々に、高笑いが止まりませんわ！', 0);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (554, 0, 2, '', 0, 0, '', 60004, 1, 2, '今日の運勢は大吉！\u3000ラッキーワードは「ぴょんぴょん♪」\\nおっきな声で一緒に言ってみよ～♪\u3000うさぎさんぴょんぴょ～ん♪', 0);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (555, 0, 2, '', 0, 0, '', 60004, 1, 2, '今日の運勢は大吉！\u3000あなたの趣味がもっと広がるかも！\\nかんわゆ～～～いショタと～騎士きゅんもゲット～んふふ～♪', 0);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (556, 0, 2, '', 0, 0, '', 60004, 1, 2, '今日の運勢は大吉！\u3000秘められた力が開花するでしょう！\u3000\u3000\u3000\u3000じゃあ、私の龍眼と力比べしてみようか？\u3000ふふ、冗談だよ～', 0);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (557, 0, 3, '', 0, 0, '', 60004, 1, 2, '今日の運勢は中吉！\u3000ラッキーアイテムはかわいいもの！\u3000\u3000\u3000\u3000ア、アタシはかわいいじゃなくてキレイだってば！\u3000も～っ！', 0);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (558, 0, 3, '', 0, 0, '', 60004, 2, 2, '今日の運勢は中吉！\u3000悩まず行動すれば強運に恵まれる！\u3000\u3000\u3000\u3000守るよりも攻めるが吉だ！\u3000勝負事をするにはいい運勢だな！', 0);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (559, 0, 3, '', 0, 0, '', 60004, 1, 2, '今日の運勢は中吉！\u3000お出かけした先で良縁に恵まれそうです！\u3000ダウナー系あざとい女子が、あま～い飴をくれるかも？', 0);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (560, 0, 3, '', 0, 0, '', 60004, 1, 2, '今日の運勢は中吉！\u3000大抵のことはゴリ押しでなんとかできます！ラッキープレイスはゲーセン。パンチングマシンでストレス発散！', 0);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (561, 0, 3, '', 0, 0, '', 60004, 1, 2, '今日の運勢は中吉！\u3000健康に気を遣って気持ちのいい一年を！\\n体に不調があるときは遠慮なく言いなさい、隅々まで調べてあげる', 0);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (562, 0, 3, '', 0, 0, '', 60004, 1, 2, '今日の運勢は中吉！\u3000歌を口ずさみ、幸運を呼び込もう！\\n幸運になれるかは分からないけど……一緒に、歌いましょ？', 0);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (563, 0, 3, '', 0, 0, '', 60004, 1, 2, '今日の運勢は中吉！\u3000誰かに尽くすことで掴める幸せもあるかも？\\n人事を尽くして天命を待つ！\u3000さ、年始もバリバリ働きますわよ♪', 0);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (564, 0, 4, '', 0, 0, '', 60004, 1, 2, '今日の運勢は小吉！\u3000難しい頼み事をされるかもしれません！\u3000\u3000うまくやれればきっと成長につながります、挑戦してみましょう！', 0);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (565, 0, 4, '', 0, 0, '', 60004, 1, 2, '今日の運勢は小吉！\u3000無理は禁物、お家で静かにしていましょう\u3000プロぼっちの私が、お家での過ごし方……教えてあげましょうか？', 0);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (566, 0, 4, '', 0, 0, '', 60004, 1, 2, '今日の運勢は小吉！\u3000思わぬ相手と仲良くなれるかも？\u3000\u3000\u3000\u3000\u3000うっかり毒舌をもらしてしまわないように要注意です！', 0);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (567, 0, 4, '', 0, 0, '', 60004, 2, 2, '今日の運勢は小吉！\u3000いろんな事件が起こる一日になりそう！\u3000\u3000状況をよく観察してみようじゃないか！\u3000まさに探偵のごとくね！', 0);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (568, 0, 4, '', 0, 0, '', 60004, 1, 2, '今日の運勢は小吉！\u3000周りに流されず、マイペースな一日を！\u3000\u3000ただし寝すぎには注意ぐうたらし過ぎず適度な運動を、だってさ～', 0);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (569, 0, 4, '', 0, 0, '', 60004, 1, 2, '今日の運勢は小吉！\u3000気の向くままに過ごすのが幸せへの近道！\u3000美味い魚を食べて猫を眺めて、自然体で過ごすのはどうだい？', 0);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (570, 0, 4, '', 0, 0, '', 60004, 2, 2, '今日の運勢は小吉！\u3000小さな勇気で踏み出す一歩が大事！\\n遠くから見てるだけじゃダメ。今日は、少しだけ近づいてみます！', 0);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (571, 2, 0, '', 190804, 0, 'カリン', 60004, 0, 3, 'おみくじの結果はどうでしたか？\\n新たに始まる一日が、あなたに\\nとって良い日になりますように\\nまた明日も遊びに来て下さいね♪', 0);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (572, 3, 0, '', 190804, 7, 'カリン', 60004, 0, 3, 'おみくじは楽しんで頂けましたか？\\nあなたの新たなる年が\\n素晴らしいものになるよう、\\n心からお祈りいたします', 0);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (573, 1, 0, '', 190804, 0, 'カリン', 60005, 1, 1, '新年を迎え、新たに始まる一日を\\nおみくじで占ってみませんか？\\n良い運勢であるほど、\\n沢山のプレゼントが貰えますよ♪', 0);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (574, 0, 1, '', 0, 0, '', 60005, 1, 2, '今日の運勢は姫吉！\u3000やること全てが最高潮！\u3000やばいですね☆\u3000ラッキーアイテムはおにぎり！\u3000お腹一杯で幸せが続くでしょう！', 0);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (575, 0, 1, '', 0, 0, '', 60005, 1, 2, '今日の運勢は姫吉！\u3000ずっと祈り続けていた願いが叶うかも！\\nきっとあんたならたどり着けるわ、ハッピーエンドのその先に', 0);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (576, 0, 1, '', 0, 0, '', 60005, 2, 2, '今日の運勢は姫吉！\u3000道を歩けば幸運に当たる、最高の吉日！\u3000\u3000さすがは兄様。尽善尽美、金甌無欠の強運をお持ちですね。', 0);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (577, 0, 1, '', 0, 0, '', 60005, 2, 2, '今日の運勢は姫吉！\u3000旅立ち、どこへ行くもよし！\u3000\u3000\u3000\u3000\u3000\u3000\u3000新年の門出も、お兄さんと一緒です♪\u3000冒険にしゅっぱーつ♪', 0);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (578, 0, 1, '', 0, 0, '', 60005, 2, 2, '今日の運勢は姫吉！\u3000一日三食食べれば健康運アップ！\u3000\u3000\u3000\u3000\u3000おせち。おぞうに。もっと、たべよ？\u3000お兄。', 0);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (579, 0, 2, '', 0, 0, '', 60005, 1, 2, '今日の運勢は大吉！\u3000あなたの趣味がもっと広がるかも！\\nかんわゆ～～～いショタと～騎士きゅんもゲット～んふふ～♪', 0);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (580, 0, 2, '', 0, 0, '', 60005, 1, 2, '今日の運勢は大吉！\u3000お裁縫好きな女の子のお墨付きです！\u3000\u3000\u3000お世話したがりの妹にめいっぱい愛されちゃうかも！？', 0);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (581, 0, 2, '', 0, 0, '', 60005, 1, 2, '今日の運勢は大吉！\u3000日々の努力が実り、何事も良い方向へ！\u3000\u3000そんな弟くんには、お姉ちゃんのよしよしぎゅ～っをプレゼント♪', 0);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (582, 0, 2, '', 0, 0, '', 60005, 2, 2, '今日の運勢は大吉！\u3000お出かけするといいことあるかも？\u3000\u3000\u3000\u3000また一緒に、お忍びデートしてくださいね……騎士♪', 0);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (583, 0, 2, '', 0, 0, '', 60005, 2, 2, '今日の運勢は大吉！\u3000転居するならあたたかい場所が吉！\u3000\u3000\u3000\u3000煉獄の世なれど、住めば都と申しんす。ゆるりときなんせ……♪', 0);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (584, 0, 3, '', 0, 0, '', 60005, 1, 2, '今日の運勢は中吉！\u3000大抵のことはゴリ押しでなんとかできます！ラッキープレイスはゲーセン。パンチングマシンでストレス発散！', 0);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (585, 0, 3, '', 0, 0, '', 60005, 1, 2, '今日の運勢は中吉！\u3000誰かに尽くすことで掴める幸せもあるかも？\\n人事を尽くして天命を待つ！\u3000さ、年始もバリバリ働きますわよ♪', 0);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (586, 0, 3, '', 0, 0, '', 60005, 1, 2, '今日の運勢は中吉！\u3000歌を口ずさみ、幸運を呼び込もう！\\n幸運になれるかは分からないけど……一緒に、歌いましょ？', 0);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (587, 0, 3, '', 0, 0, '', 60005, 1, 2, '今日の運勢は中吉！\u3000健康に気を遣って気持ちのいい一年を！\\n体に不調があるときは遠慮なく言いなさい、隅々まで調べてあげる', 0);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (588, 0, 3, '', 0, 0, '', 60005, 1, 2, '今日の運勢は中吉！\u3000旅行運がぐんぐんと上昇中♪\u3000\u3000\u3000\u3000\u3000\u3000\u3000もしかしたら、あの「マホマホ王国」にだって行けるかも♪', 0);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (589, 0, 3, '', 0, 0, '', 60005, 2, 2, '今日の運勢は中吉！\u3000争いごとは勝つが油断は大敵！\u3000\u3000\u3000\u3000\u3000\u3000ま、このあたしと一緒なら、向かうところ敵はねーですよっ！', 0);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (590, 0, 3, '', 0, 0, '', 60005, 2, 2, '今日の運勢は中吉！\u3000ラッキーアイテムは「光るもの」！\u3000\u3000\u3000\u3000ハツネちゃんの「きらーんっ☆」な魔法、見せちゃおうかなっ？', 0);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (591, 0, 4, '', 0, 0, '', 60005, 1, 2, '今日の運勢は小吉！\u3000のんびり穏やかな一日となるでしょう！\u3000\u3000あなた様を邪魔するものは全てエリコが排除しますわ、クスクス♪', 0);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (592, 0, 4, '', 0, 0, '', 60005, 1, 2, '今日の運勢は小吉！\u3000小さな勇気で踏み出す一歩が大事！\\n遠くから見てるだけじゃダメ。今日は、少しだけ近づいてみます！', 0);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (593, 0, 4, '', 0, 0, '', 60005, 1, 2, '今日の運勢は小吉！\u3000外に出てゆっくり過ごすと運気が上昇！\u3000\u3000ラッキースポットは牧場。面白い出会いがありそうです♪', 0);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (594, 0, 4, '', 0, 0, '', 60005, 1, 2, '今日の運勢は小吉！\u3000いろんな事件が起こる一日になりそう！\u3000\u3000状況をよく観察してみようじゃないか！\u3000まさに探偵のごとくね！', 0);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (595, 0, 4, '', 0, 0, '', 60005, 1, 2, '今日の運勢は小吉！\u3000難しい頼み事をされるかもしれません！\u3000\u3000うまくやれればきっと成長につながります、挑戦してみましょう！', 0);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (596, 0, 4, '', 0, 0, '', 60005, 2, 2, '今日の運勢は小吉！\u3000空を眺めると気持ちが晴れやかに！\u3000\u3000\u3000\u3000眺めるだけじゃなくて、ひとっ飛びしちゃいましょうかっ♪', 0);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (597, 0, 4, '', 0, 0, '', 60005, 2, 2, '今日の運勢は小吉！\u3000掃除をすると運勢が開けそう！\u3000\u3000\u3000\u3000\u3000\u3000「わ、めんど」「ヴルムっ！\u3000新年早々サボっちゃダメなんだからね！」', 0);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (598, 2, 0, '', 190804, 0, 'カリン', 60005, 0, 3, 'おみくじの結果はどうでしたか？\\n新たに始まる一日が、あなたに\\nとって良い日になりますように\\nまた明日も遊びに来て下さいね♪', 0);
insert into v1_8d315da1f41da15ab5768ec99230e923726c852670cf000ce16cd691183635fc values (599, 3, 0, '', 190804, 7, 'カリン', 60005, 0, 3, 'おみくじは楽しんで頂けましたか？\\nあなたの新たなる年が\\n素晴らしいものになるよう、\\n心からお祈りいたします', 0);
